{
  "name": "Gemini Starfighter",
  "description": "An infinite arcade space shooter where enemy waves and boss encounters are procedurally generated by Gemini AI based on your performance."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GameState {
  MENU,
  PLAYING,
  PAUSED,
  GAME_OVER
}

export interface Point {
  x: number;
  y: number;
}

export interface Entity {
  id: number;
  x: number;
  y: number;
  width: number;
  height: number;
  color: string;
  vx: number;
  vy: number;
  markedForDeletion: boolean;
}

export interface Player extends Entity {
  hp: number;
  maxHp: number;
  weaponLevel: number;
  score: number;
  invulnerableUntil: number;
}

export interface Enemy extends Entity {
  hp: number;
  maxHp: number;
  type: 'scout' | 'fighter' | 'tank' | 'boss';
  scoreValue: number;
}

export interface Projectile extends Entity {
  damage: number;
  isEnemy: boolean;
}

export interface Particle extends Entity {
  life: number;
  maxLife: number;
  size: number;
}

export interface WaveConfig {
  enemies: {
    type: 'scout' | 'fighter' | 'tank' | 'boss';
    count: number;
    speed: number;
    hp: number;
    color: string;
  }[];
  flavorText: string;
}

export interface GameStats {
  score: number;
  level: number;
  enemiesDefeated: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { WaveConfig } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const modelName = 'gemini-2.5-flash';

// Fallback wave if API fails or for first level
export const fallbackWave: WaveConfig = {
  enemies: [
    { type: 'scout', count: 5, speed: 2, hp: 10, color: '#34d399' },
    { type: 'fighter', count: 2, speed: 1.5, hp: 30, color: '#60a5fa' }
  ],
  flavorText: "System initialized. Engaging standard defense protocols."
};

export const generateWave = async (level: number, playerPerformance: string): Promise<WaveConfig> => {
  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: `
        Generate a wave of enemies for a space shooter game.
        Current Level: ${level}.
        Player Performance Context: ${playerPerformance}.

        Rules:
        - As level increases, enemies should get harder (more HP, speed, or count).
        - 'scout' are fast/weak, 'fighter' are balanced, 'tank' are slow/tough, 'boss' is very strong (only 1 per wave usually).
        - Colors should be hex codes valid in CSS.
        - Provide a short, sci-fi military style flavor text describing the incoming threat.
        - Enemy count should be reasonable (total 5-20 usually).
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            enemies: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING, enum: ['scout', 'fighter', 'tank', 'boss'] },
                  count: { type: Type.NUMBER },
                  speed: { type: Type.NUMBER },
                  hp: { type: Type.NUMBER },
                  color: { type: Type.STRING }
                },
                required: ['type', 'count', 'speed', 'hp', 'color']
              }
            },
            flavorText: { type: Type.STRING }
          },
          required: ['enemies', 'flavorText']
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as WaveConfig;
    }
    return fallbackWave;
  } catch (error) {
    console.error("Gemini generation failed:", error);
    return fallbackWave;
  }
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GameState, Player, Enemy, Projectile, Particle, WaveConfig } from '../types';
import { generateWave, fallbackWave } from '../services/geminiService';

interface GameCanvasProps {
  gameState: GameState;
  setGameState: (state: GameState) => void;
  setScore: (score: number) => void;
  setLives: (lives: number) => void;
  setLevel: (level: number) => void;
  setFlavorText: (text: string) => void;
  onGameOver: (finalScore: number) => void;
}

const CANVAS_WIDTH = 800;
const CANVAS_HEIGHT = 600;

export const GameCanvas: React.FC<GameCanvasProps> = ({
  gameState,
  setGameState,
  setScore,
  setLives,
  setLevel,
  setFlavorText,
  onGameOver
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Mutable game state refs to avoid closure staleness in loop
  const playerRef = useRef<Player>({
    id: 0, x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT - 50,
    width: 40, height: 40, color: '#3b82f6',
    vx: 0, vy: 0, markedForDeletion: false,
    hp: 100, maxHp: 100, weaponLevel: 1, score: 0, invulnerableUntil: 0
  });

  const enemiesRef = useRef<Enemy[]>([]);
  const projectilesRef = useRef<Projectile[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const keysRef = useRef<{ [key: string]: boolean }>({});

  const levelRef = useRef(1);
  const wavePendingRef = useRef(false);
  const frameRef = useRef(0);
  const nextWaveConfigRef = useRef<WaveConfig | null>(null);

  // Initialize controls
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      keysRef.current[e.code] = true;
      if (e.code === 'Escape' && gameState === GameState.PLAYING) {
        setGameState(GameState.PAUSED);
      } else if (e.code === 'Escape' && gameState === GameState.PAUSED) {
        setGameState(GameState.PLAYING);
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      keysRef.current[e.code] = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [gameState, setGameState]);

  // Pre-fetch next wave
  const queueNextWave = useCallback(async () => {
    if (wavePendingRef.current) return;
    wavePendingRef.current = true;

    // Determine context for AI
    const healthPercent = Math.round((playerRef.current.hp / playerRef.current.maxHp) * 100);
    const context = `Player HP: ${healthPercent}%, Score: ${playerRef.current.score}. If HP is high, make it harder. If low, give a slight break.`;

    try {
      const wave = await generateWave(levelRef.current + 1, context);
      nextWaveConfigRef.current = wave;
    } catch (e) {
      nextWaveConfigRef.current = fallbackWave;
    } finally {
      wavePendingRef.current = false;
    }
  }, []);

  // Spawn a wave
  const spawnWave = useCallback((config: WaveConfig) => {
    setFlavorText(config.flavorText);
    const newEnemies: Enemy[] = [];
    let idCounter = Date.now();

    config.enemies.forEach((group) => {
      for (let i = 0; i < group.count; i++) {
        newEnemies.push({
          id: idCounter++,
          x: Math.random() * (CANVAS_WIDTH - 60) + 30,
          y: -Math.random() * 200 - 50, // Spawn above screen staggered
          width: group.type === 'boss' ? 100 : (group.type === 'tank' ? 60 : 40),
          height: group.type === 'boss' ? 100 : (group.type === 'tank' ? 60 : 40),
          color: group.color,
          vx: (Math.random() - 0.5) * group.speed,
          vy: group.speed * 0.5,
          markedForDeletion: false,
          hp: group.hp,
          maxHp: group.hp,
          type: group.type,
          scoreValue: group.hp * 10
        });
      }
    });
    enemiesRef.current = [...enemiesRef.current, ...newEnemies];
  }, [setFlavorText]);

  // Reset Game
  const resetGame = useCallback(() => {
    playerRef.current = {
      id: 0, x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT - 60,
      width: 40, height: 40, color: '#3b82f6',
      vx: 0, vy: 0, markedForDeletion: false,
      hp: 100, maxHp: 100, weaponLevel: 1, score: 0, invulnerableUntil: 0
    };
    enemiesRef.current = [];
    projectilesRef.current = [];
    particlesRef.current = [];
    levelRef.current = 1;
    setScore(0);
    setLives(100);
    setLevel(1);

    // Initial Wave
    spawnWave(fallbackWave);
    queueNextWave(); // Start fetching level 2 immediately
  }, [setScore, setLives, setLevel, queueNextWave, spawnWave]);

  // Start game when state changes to PLAYING for the first time
  useEffect(() => {
    if (gameState === GameState.PLAYING && enemiesRef.current.length === 0 && playerRef.current.score === 0) {
      resetGame();
    }
  }, [gameState, resetGame]);

  // Main Game Loop
  useEffect(() => {
    if (gameState !== GameState.PLAYING) return;

    let animationFrameId: number;
    let lastTime = performance.now();
    let fireCooldown = 0;

    const spawnParticle = (x: number, y: number, color: string, count: number = 5) => {
      for (let i = 0; i < count; i++) {
        particlesRef.current.push({
          id: Math.random(),
          x, y,
          width: 0, height: 0, // unused for particles usually
          vx: (Math.random() - 0.5) * 10,
          vy: (Math.random() - 0.5) * 10,
          color,
          life: 1.0,
          maxLife: 1.0,
          size: Math.random() * 4 + 2,
          markedForDeletion: false
        });
      }
    };

    const update = (time: number) => {
      const dt = (time - lastTime) / 1000;
      lastTime = time;

      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');

      if (!canvas || !ctx) return;

      // Clear canvas
      ctx.fillStyle = '#050505';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // --- PLAYER UPDATE ---
      const player = playerRef.current;
      const speed = 300;
      if (keysRef.current['ArrowLeft'] || keysRef.current['KeyA']) player.x -= speed * dt;
      if (keysRef.current['ArrowRight'] || keysRef.current['KeyD']) player.x += speed * dt;
      if (keysRef.current['ArrowUp'] || keysRef.current['KeyW']) player.y -= speed * dt;
      if (keysRef.current['ArrowDown'] || keysRef.current['KeyS']) player.y += speed * dt;

      // Clamp player
      player.x = Math.max(0, Math.min(CANVAS_WIDTH - player.width, player.x));
      player.y = Math.max(0, Math.min(CANVAS_HEIGHT - player.height, player.y));

      // Shooting
      if (keysRef.current['Space']) {
        if (fireCooldown <= 0) {
          projectilesRef.current.push({
            id: Math.random(),
            x: player.x + player.width / 2 - 2,
            y: player.y,
            width: 4, height: 12,
            color: '#fbbf24',
            vx: 0, vy: -600,
            markedForDeletion: false,
            damage: 10,
            isEnemy: false
          });
          fireCooldown = 0.15; // Refire rate
        }
      }
      fireCooldown -= dt;

      // --- PROJECTILES ---
      projectilesRef.current.forEach(p => {
        p.x += p.vx * dt;
        p.y += p.vy * dt;
        if (p.y < -50 || p.y > CANVAS_HEIGHT + 50) p.markedForDeletion = true;
      });

      // --- ENEMIES ---
      // Check wave clear
      if (enemiesRef.current.length === 0) {
         if (nextWaveConfigRef.current) {
             levelRef.current++;
             setLevel(levelRef.current);
             spawnWave(nextWaveConfigRef.current);
             nextWaveConfigRef.current = null;
             queueNextWave();
         } else if (!wavePendingRef.current) {
             // If we ran out of enemies and no wave is ready, force fetch or wait
             // For now, let's just wait, queueNextWave should be running.
             // If it takes too long, queueNextWave handles it.
             queueNextWave();
         }
      }

      enemiesRef.current.forEach(enemy => {
        // Movement
        enemy.y += enemy.vy * 60 * dt; // Simple downward
        enemy.x += Math.sin(time / 500 + enemy.id) * 2; // Wiggle

        if (enemy.y > CANVAS_HEIGHT) {
          // Enemy passed player
          enemy.markedForDeletion = true;
          player.score = Math.max(0, player.score - 50); // Penalty
        }

        // Enemy Shooting (Random)
        if (Math.random() < 0.005 * (levelRef.current * 0.5)) {
           projectilesRef.current.push({
            id: Math.random(),
            x: enemy.x + enemy.width / 2,
            y: enemy.y + enemy.height,
            width: 6, height: 12,
            color: '#ef4444',
            vx: 0, vy: 300,
            markedForDeletion: false,
            damage: 10,
            isEnemy: true
          });
        }
      });

      // --- COLLISION ---
      // 1. Projectile hits Enemy/Player
      projectilesRef.current.forEach(proj => {
        if (proj.markedForDeletion) return;

        if (proj.isEnemy) {
            // Hit Player
            if (
                proj.x < player.x + player.width &&
                proj.x + proj.width > player.x &&
                proj.y < player.y + player.height &&
                proj.y + proj.height > player.y
            ) {
                 if (Date.now() > player.invulnerableUntil) {
                     player.hp -= proj.damage;
                     proj.markedForDeletion = true;
                     spawnParticle(player.x + player.width/2, player.y + player.height/2, '#ef4444', 10);
                     if (player.hp <= 0) {
                         onGameOver(player.score);
                     }
                     setLives(player.hp);
                 }
            }
        } else {
            // Hit Enemy
            enemiesRef.current.forEach(enemy => {
                if (
                    proj.x < enemy.x + enemy.width &&
                    proj.x + proj.width > enemy.x &&
                    proj.y < enemy.y + enemy.height &&
                    proj.y + proj.height > enemy.y
                ) {
                    enemy.hp -= proj.damage;
                    proj.markedForDeletion = true;
                    spawnParticle(proj.x, proj.y, '#fbbf24', 3);

                    if (enemy.hp <= 0) {
                        enemy.markedForDeletion = true;
                        player.score += enemy.scoreValue;
                        spawnParticle(enemy.x + enemy.width/2, enemy.y + enemy.height/2, enemy.color, 15);
                    }
                }
            });
        }
      });

      setScore(player.score);

      // --- PARTICLES ---
      particlesRef.current.forEach(p => {
        p.x += p.vx;
        p.y += p.vy;
        p.life -= dt * 2;
        if (p.life <= 0) p.markedForDeletion = true;
      });

      // Cleanup
      enemiesRef.current = enemiesRef.current.filter(e => !e.markedForDeletion);
      projectilesRef.current = projectilesRef.current.filter(p => !p.markedForDeletion);
      particlesRef.current = particlesRef.current.filter(p => !p.markedForDeletion);

      // --- DRAWING ---

      // Draw Player
      if (player.hp > 0) {
          ctx.fillStyle = player.color;
          // Simple ship shape
          ctx.beginPath();
          ctx.moveTo(player.x + player.width/2, player.y);
          ctx.lineTo(player.x + player.width, player.y + player.height);
          ctx.lineTo(player.x + player.width/2, player.y + player.height - 10);
          ctx.lineTo(player.x, player.y + player.height);
          ctx.closePath();
          ctx.fill();

          // Engine flame
          ctx.fillStyle = `rgba(255, 100, 0, ${Math.random()})`;
          ctx.beginPath();
          ctx.moveTo(player.x + player.width/2 - 5, player.y + player.height - 5);
          ctx.lineTo(player.x + player.width/2 + 5, player.y + player.height - 5);
          ctx.lineTo(player.x + player.width/2, player.y + player.height + Math.random() * 20);
          ctx.fill();
      }

      // Draw Enemies
      enemiesRef.current.forEach(e => {
          ctx.fillStyle = e.color;
          ctx.fillRect(e.x, e.y, e.width, e.height);

          // HP Bar for tank/boss
          if (e.maxHp > 20) {
              const hpPct = e.hp / e.maxHp;
              ctx.fillStyle = 'red';
              ctx.fillRect(e.x, e.y - 10, e.width, 4);
              ctx.fillStyle = 'green';
              ctx.fillRect(e.x, e.y - 10, e.width * hpPct, 4);
          }
      });

      // Draw Projectiles
      projectilesRef.current.forEach(p => {
          ctx.fillStyle = p.color;
          ctx.fillRect(p.x, p.y, p.width, p.height);
      });

      // Draw Particles
      particlesRef.current.forEach(p => {
          ctx.globalAlpha = p.life;
          ctx.fillStyle = p.color;
          ctx.fillRect(p.x, p.y, p.size, p.size);
          ctx.globalAlpha = 1.0;
      });

      animationFrameId = requestAnimationFrame(update);
    };

    animationFrameId = requestAnimationFrame(update);
    return () => cancelAnimationFrame(animationFrameId);
  }, [gameState, onGameOver, setLives, setScore, spawnWave, queueNextWave, setLevel]);

  return (
    <div className="relative rounded-lg overflow-hidden shadow-2xl border-2 border-slate-800">
      <canvas
        ref={canvasRef}
        width={CANVAS_WIDTH}
        height={CANVAS_HEIGHT}
        className="bg-black block w-full max-w-[800px] h-auto"
      />
      <div className="scanlines"></div>

      {/* Wave Loading Indicator */}
      {enemiesRef.current.length === 0 && gameState === GameState.PLAYING && (
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-green-400 font-mono text-xl animate-pulse">
          SCANNING FOR HOSTILES...
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { GameCanvas } from './components/GameCanvas';
import { GameState } from './types';
import { GoogleGenAI } from '@google/genai';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0);
  const [lives, setLives] = useState(100);
  const [level, setLevel] = useState(1);
  const [flavorText, setFlavorText] = useState("System online. Waiting for pilot input.");
  const [highScore, setHighScore] = useState(0);

  const handleStartGame = () => {
    setGameState(GameState.PLAYING);
  };

  const handleGameOver = (finalScore: number) => {
    setGameState(GameState.GAME_OVER);
    if (finalScore > highScore) setHighScore(finalScore);
  };

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-4">
      {/* Header / HUD */}
      <div className="w-full max-w-[800px] flex justify-between items-end mb-4 font-mono">
        <div>
          <h1 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-blue-600">
            GEMINI STARFIGHTER
          </h1>
          <p className="text-slate-400 text-sm mt-1 h-6">{flavorText}</p>
        </div>
        <div className="text-right">
           <div className="text-sm text-slate-500">SCORE</div>
           <div className="text-2xl text-white font-bold tracking-widest">{score.toString().padStart(6, '0')}</div>
        </div>
      </div>

      {/* Main Game Container */}
      <div className="relative group">
        <GameCanvas 
          gameState={gameState}
          setGameState={setGameState}
          setScore={setScore}
          setLives={setLives}
          setLevel={setLevel}
          setFlavorText={setFlavorText}
          onGameOver={handleGameOver}
        />

        {/* Start Menu Overlay */}
        {gameState === GameState.MENU && (
          <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center z-20 backdrop-blur-sm">
            <h2 className="text-5xl font-bold text-white mb-8 tracking-tighter">READY PLAYER ONE</h2>
            <button 
              onClick={handleStartGame}
              className="px-8 py-4 bg-cyan-600 hover:bg-cyan-500 text-white font-bold rounded-none border-2 border-cyan-400 shadow-[0_0_20px_rgba(34,211,238,0.5)] transition-all transform hover:scale-105 active:scale-95 text-xl"
            >
              INITIATE LAUNCH
            </button>
            <p className="text-slate-500 mt-8 font-mono text-sm">
              WASD / ARROWS to Move • SPACE to Shoot
            </p>
          </div>
        )}

        {/* Game Over Overlay */}
        {gameState === GameState.GAME_OVER && (
          <div className="absolute inset-0 bg-red-950/80 flex flex-col items-center justify-center text-center z-20 backdrop-blur-sm">
            <h2 className="text-5xl font-bold text-red-500 mb-2">MISSION FAILED</h2>
            <p className="text-xl text-white mb-6">FINAL SCORE: {score}</p>
            <button 
              onClick={handleStartGame}
              className="px-8 py-4 bg-red-600 hover:bg-red-500 text-white font-bold border-2 border-red-400 shadow-[0_0_20px_rgba(248,113,113,0.5)] transition-all transform hover:scale-105 active:scale-95"
            >
              RETRY MISSION
            </button>
          </div>
        )}

        {/* Pause Overlay */}
         {gameState === GameState.PAUSED && (
          <div className="absolute inset-0 bg-black/60 flex flex-col items-center justify-center text-center z-20 backdrop-blur-sm">
            <h2 className="text-4xl font-bold text-yellow-400 mb-8 tracking-widest">SYSTEM PAUSED</h2>
            <button 
              onClick={() => setGameState(GameState.PLAYING)}
              className="px-8 py-3 bg-yellow-600 hover:bg-yellow-500 text-white font-bold border-2 border-yellow-400 transition-all"
            >
              RESUME
            </button>
          </div>
        )}

        {/* HUD Overlay inside relative container */}
        {gameState === GameState.PLAYING && (
           <>
            {/* Health Bar */}
            <div className="absolute bottom-4 left-4 z-10 w-48">
              <div className="text-xs text-cyan-400 mb-1 font-mono">HULL INTEGRITY</div>
              <div className="h-4 bg-slate-800 border border-slate-600 w-full relative">
                <div 
                  className="h-full bg-gradient-to-r from-red-500 to-green-500 transition-all duration-300" 
                  style={{ width: `${Math.max(0, Math.min(100, lives))}%` }}
                ></div>
              </div>
            </div>

            {/* Level Indicator */}
            <div className="absolute bottom-4 right-4 z-10 text-right">
              <div className="text-xs text-cyan-400 mb-1 font-mono">THREAT LEVEL</div>
              <div className="text-2xl font-bold text-white font-mono">{level}</div>
            </div>
           </>
        )}
      </div>

      <div className="mt-8 text-slate-600 text-xs text-center font-mono max-w-lg">
        <p>Powered by Google Gemini AI</p>
        <p>Procedurally generated enemy waves based on tactical analysis.</p>
      </div>
    </div>
  );
};

export default App;

export enum GameState {
  MENU,
  PLAYING,
  PAUSED,
  GAME_OVER
}

export interface Point {
  x: number;
  y: number;
}

export interface Entity {
  id: number;
  x: number;
  y: number;
  width: number;
  height: number;
  color: string;
  vx: number;
  vy: number;
  markedForDeletion: boolean;
}

export interface Player extends Entity {
  hp: number;
  maxHp: number;
  weaponLevel: number;
  score: number;
  invulnerableUntil: number;
  rotation: number;
}

export interface Enemy extends Entity {
  hp: number;
  maxHp: number;
  type: 'scout' | 'fighter' | 'tank' | 'boss';
  scoreValue: number;
}

export interface Projectile extends Entity {
  damage: number;
  isEnemy: boolean;
}

export interface Particle extends Entity {
  life: number;
  maxLife: number;
  size: number;
}

export interface WaveConfig {
  enemies: {
    type: 'scout' | 'fighter' | 'tank' | 'boss';
    count: number;
    speed: number;
    hp: number;
    color: string;
  }[];
  flavorText: string;
}

export interface GameStats {
  score: number;
  level: number;
  enemiesDefeated: number;
}

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GameState, Player, Enemy, Projectile, Particle, WaveConfig } from '../types';
import { generateWave, fallbackWave } from '../services/geminiService';

interface GameCanvasProps {
  gameState: GameState;
  setGameState: (state: GameState) => void;
  setScore: (score: number) => void;
  setLives: (lives: number) => void;
  setLevel: (level: number) => void;
  setFlavorText: (text: string) => void;
  onGameOver: (finalScore: number) => void;
}

const CANVAS_WIDTH = 800;
const CANVAS_HEIGHT = 600;

export const GameCanvas: React.FC<GameCanvasProps> = ({
  gameState,
  setGameState,
  setScore,
  setLives,
  setLevel,
  setFlavorText,
  onGameOver
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Mutable game state refs
  const playerRef = useRef<Player>({
    id: 0, x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT - 100,
    width: 30, height: 30, color: '#3b82f6',
    vx: 0, vy: 0, markedForDeletion: false,
    hp: 100, maxHp: 100, weaponLevel: 1, score: 0, invulnerableUntil: 0,
    rotation: -Math.PI / 2 // Default facing up
  });

  const enemiesRef = useRef<Enemy[]>([]);
  const projectilesRef = useRef<Projectile[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const keysRef = useRef<{ [key: string]: boolean }>({});

  // Mouse state
  const mouseRef = useRef({ x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2 });
  const mouseDownRef = useRef(false);

  const levelRef = useRef(1);
  const wavePendingRef = useRef(false);
  const nextWaveConfigRef = useRef<WaveConfig | null>(null);

  // Initialize controls
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      keysRef.current[e.code] = true;
      if (e.code === 'Escape' && gameState === GameState.PLAYING) {
        setGameState(GameState.PAUSED);
      } else if (e.code === 'Escape' && gameState === GameState.PAUSED) {
        setGameState(GameState.PLAYING);
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      keysRef.current[e.code] = false;
    };

    const handleMouseMove = (e: MouseEvent) => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      // Calculate scale in case canvas is resized via CSS
      const scaleX = canvas.width / rect.width;
      const scaleY = canvas.height / rect.height;

      mouseRef.current = {
        x: (e.clientX - rect.left) * scaleX,
        y: (e.clientY - rect.top) * scaleY
      };
    };

    const handleMouseDown = (e: MouseEvent) => {
      if (e.button === 0) mouseDownRef.current = true;
    };

    const handleMouseUp = () => {
      mouseDownRef.current = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    // Bind mouse events to window to catch drags outside canvas, or canvas specifically if preferred. 
    // Using window for smoother aiming.
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [gameState, setGameState]);

  // Pre-fetch next wave
  const queueNextWave = useCallback(async () => {
    if (wavePendingRef.current) return;
    wavePendingRef.current = true;

    const healthPercent = Math.round((playerRef.current.hp / playerRef.current.maxHp) * 100);
    const context = `Player HP: ${healthPercent}%, Score: ${playerRef.current.score}. If HP is high, make it harder.`;

    try {
      const wave = await generateWave(levelRef.current + 1, context);
      nextWaveConfigRef.current = wave;
    } catch (e) {
      nextWaveConfigRef.current = fallbackWave;
    } finally {
      wavePendingRef.current = false;
    }
  }, []);

  // Spawn a wave
  const spawnWave = useCallback((config: WaveConfig) => {
    setFlavorText(config.flavorText);
    const newEnemies: Enemy[] = [];
    let idCounter = Date.now();

    config.enemies.forEach((group) => {
      for (let i = 0; i < group.count; i++) {
        newEnemies.push({
          id: idCounter++,
          x: Math.random() * (CANVAS_WIDTH - 60) + 30,
          y: -Math.random() * 200 - 50, 
          width: group.type === 'boss' ? 100 : (group.type === 'tank' ? 60 : 40),
          height: group.type === 'boss' ? 100 : (group.type === 'tank' ? 60 : 40),
          color: group.color,
          vx: (Math.random() - 0.5) * group.speed,
          vy: group.speed * 0.5,
          markedForDeletion: false,
          hp: group.hp,
          maxHp: group.hp,
          type: group.type,
          scoreValue: group.hp * 10
        });
      }
    });
    enemiesRef.current = [...enemiesRef.current, ...newEnemies];
  }, [setFlavorText]);

  // Reset Game
  const resetGame = useCallback(() => {
    playerRef.current = {
      id: 0, x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT - 100,
      width: 30, height: 30, color: '#3b82f6',
      vx: 0, vy: 0, markedForDeletion: false,
      hp: 100, maxHp: 100, weaponLevel: 1, score: 0, invulnerableUntil: 0,
      rotation: -Math.PI / 2
    };
    enemiesRef.current = [];
    projectilesRef.current = [];
    particlesRef.current = [];
    levelRef.current = 1;
    setScore(0);
    setLives(100);
    setLevel(1);

    spawnWave(fallbackWave);
    queueNextWave();
  }, [setScore, setLives, setLevel, queueNextWave, spawnWave]);

  useEffect(() => {
    if (gameState === GameState.PLAYING && enemiesRef.current.length === 0 && playerRef.current.score === 0) {
      resetGame();
    }
  }, [gameState, resetGame]);

  // Main Game Loop
  useEffect(() => {
    if (gameState !== GameState.PLAYING) return;

    let animationFrameId: number;
    let lastTime = performance.now();
    let fireCooldown = 0;

    const spawnParticle = (x: number, y: number, color: string, count: number = 5) => {
      for (let i = 0; i < count; i++) {
        particlesRef.current.push({
          id: Math.random(),
          x, y,
          width: 0, height: 0,
          vx: (Math.random() - 0.5) * 10,
          vy: (Math.random() - 0.5) * 10,
          color,
          life: 1.0,
          maxLife: 1.0,
          size: Math.random() * 4 + 2,
          markedForDeletion: false
        });
      }
    };

    const update = (time: number) => {
      const dt = (time - lastTime) / 1000;
      lastTime = time;

      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');

      if (!canvas || !ctx) return;

      // Clear canvas
      ctx.fillStyle = '#050505';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // --- PLAYER UPDATE ---
      const player = playerRef.current;
      const speed = 300;

      // Movement
      if (keysRef.current['ArrowLeft'] || keysRef.current['KeyA']) player.x -= speed * dt;
      if (keysRef.current['ArrowRight'] || keysRef.current['KeyD']) player.x += speed * dt;
      if (keysRef.current['ArrowUp'] || keysRef.current['KeyW']) player.y -= speed * dt;
      if (keysRef.current['ArrowDown'] || keysRef.current['KeyS']) player.y += speed * dt;

      // Clamp player
      player.x = Math.max(0, Math.min(CANVAS_WIDTH - player.width, player.x));
      player.y = Math.max(0, Math.min(CANVAS_HEIGHT - player.height, player.y));

      // Rotation (Aim at mouse)
      const centerX = player.x + player.width / 2;
      const centerY = player.y + player.height / 2;
      const dx = mouseRef.current.x - centerX;
      const dy = mouseRef.current.y - centerY;
      player.rotation = Math.atan2(dy, dx);

      // Shooting (Mouse Click)
      if (mouseDownRef.current) {
        if (fireCooldown <= 0) {
          // Fire from the "gun" position which is slightly offset in direction of rotation
          const gunLength = 25;
          const spawnX = centerX + Math.cos(player.rotation) * gunLength;
          const spawnY = centerY + Math.sin(player.rotation) * gunLength;

          projectilesRef.current.push({
            id: Math.random(),
            x: spawnX,
            y: spawnY,
            width: 8, height: 8, // Square bullets for simplicity or rotated lines
            color: '#fbbf24',
            vx: Math.cos(player.rotation) * 800,
            vy: Math.sin(player.rotation) * 800,
            markedForDeletion: false,
            damage: 10,
            isEnemy: false
          });

          // Recoil push?
          // player.x -= Math.cos(player.rotation) * 2;
          // player.y -= Math.sin(player.rotation) * 2;

          fireCooldown = 0.12; 
        }
      }
      fireCooldown -= dt;

      // --- PROJECTILES ---
      projectilesRef.current.forEach(p => {
        p.x += p.vx * dt;
        p.y += p.vy * dt;
        if (p.x < -50 || p.x > CANVAS_WIDTH + 50 || p.y < -50 || p.y > CANVAS_HEIGHT + 50) {
          p.markedForDeletion = true;
        }
      });

      // --- ENEMIES ---
      if (enemiesRef.current.length === 0) {
         if (nextWaveConfigRef.current) {
             levelRef.current++;
             setLevel(levelRef.current);
             spawnWave(nextWaveConfigRef.current);
             nextWaveConfigRef.current = null;
             queueNextWave();
         } else if (!wavePendingRef.current) {
             queueNextWave();
         }
      }

      enemiesRef.current.forEach(enemy => {
        // Enemies slowly drift down but maybe track player X slightly
        enemy.y += enemy.vy * 60 * dt; 
        enemy.x += Math.sin(time / 500 + enemy.id) * 2; 

        if (enemy.y > CANVAS_HEIGHT) {
          enemy.markedForDeletion = true;
          player.score = Math.max(0, player.score - 50); 
        }

        // Enemy Shooting
        if (Math.random() < 0.005 * (levelRef.current * 0.5)) {
           // Enemies aim at player
           const ex = enemy.x + enemy.width/2;
           const ey = enemy.y + enemy.height;
           const angleToPlayer = Math.atan2(player.y - ey, player.x - ex);

           // If it's a "dumb" enemy, just shoot down, otherwise aim
           const isSmart = levelRef.current > 2 && Math.random() > 0.5;
           const vx = isSmart ? Math.cos(angleToPlayer) * 300 : 0;
           const vy = isSmart ? Math.sin(angleToPlayer) * 300 : 300;

           projectilesRef.current.push({
            id: Math.random(),
            x: ex,
            y: ey,
            width: 6, height: 6,
            color: '#ef4444',
            vx: vx, vy: vy,
            markedForDeletion: false,
            damage: 10,
            isEnemy: true
          });
        }
      });

      // --- COLLISION ---
      // AABB Collision (simplified, ignores rotation for Hitbox to keep it cheap)
      projectilesRef.current.forEach(proj => {
        if (proj.markedForDeletion) return;

        if (proj.isEnemy) {
            // Hit Player
            if (
                proj.x < player.x + player.width &&
                proj.x + proj.width > player.x &&
                proj.y < player.y + player.height &&
                proj.y + proj.height > player.y
            ) {
                 if (Date.now() > player.invulnerableUntil) {
                     player.hp -= proj.damage;
                     proj.markedForDeletion = true;
                     spawnParticle(player.x + player.width/2, player.y + player.height/2, '#ef4444', 10);
                     if (player.hp <= 0) {
                         onGameOver(player.score);
                     }
                     setLives(player.hp);
                 }
            }
        } else {
            // Hit Enemy
            enemiesRef.current.forEach(enemy => {
                if (
                    proj.x < enemy.x + enemy.width &&
                    proj.x + proj.width > enemy.x &&
                    proj.y < enemy.y + enemy.height &&
                    proj.y + proj.height > enemy.y
                ) {
                    enemy.hp -= proj.damage;
                    proj.markedForDeletion = true;
                    spawnParticle(proj.x, proj.y, '#fbbf24', 3);

                    if (enemy.hp <= 0) {
                        enemy.markedForDeletion = true;
                        player.score += enemy.scoreValue;
                        spawnParticle(enemy.x + enemy.width/2, enemy.y + enemy.height/2, enemy.color, 15);
                    }
                }
            });
        }
      });

      setScore(player.score);

      // --- PARTICLES ---
      particlesRef.current.forEach(p => {
        p.x += p.vx;
        p.y += p.vy;
        p.life -= dt * 2;
        if (p.life <= 0) p.markedForDeletion = true;
      });

      // Cleanup
      enemiesRef.current = enemiesRef.current.filter(e => !e.markedForDeletion);
      projectilesRef.current = projectilesRef.current.filter(p => !p.markedForDeletion);
      particlesRef.current = particlesRef.current.filter(p => !p.markedForDeletion);

      // --- DRAWING ---

      // Draw Player (Rotated)
      if (player.hp > 0) {
          ctx.save();
          const cx = player.x + player.width / 2;
          const cy = player.y + player.height / 2;
          ctx.translate(cx, cy);
          ctx.rotate(player.rotation);

          // Body (Circle)
          ctx.fillStyle = player.color;
          ctx.beginPath();
          ctx.arc(0, 0, player.width / 2, 0, Math.PI * 2);
          ctx.fill();

          // Gun (Rectangle)
          ctx.fillStyle = '#1e3a8a'; // Darker blue gun
          ctx.fillRect(0, -4, 25, 8); // Gun sticking out to the "right" (0 degrees)

          // Shoulders/Armor detail
          ctx.fillStyle = '#60a5fa';
          ctx.fillRect(-10, -12, 10, 24); // Backpack/Armor

          // Helmet Visor
          ctx.fillStyle = '#bfdbfe';
          ctx.beginPath();
          ctx.arc(4, 0, 6, -Math.PI/4, Math.PI/4);
          ctx.fill();

          ctx.restore();

          // Aim line (optional, maybe too cluttered?)
          // ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
          // ctx.beginPath();
          // ctx.moveTo(cx, cy);
          // ctx.lineTo(mouseRef.current.x, mouseRef.current.y);
          // ctx.stroke();
      }

      // Draw Enemies
      enemiesRef.current.forEach(e => {
          ctx.fillStyle = e.color;
          ctx.fillRect(e.x, e.y, e.width, e.height);

          // Simple eyes to make them look like ships/aliens
          ctx.fillStyle = 'rgba(0,0,0,0.3)';
          ctx.fillRect(e.x + e.width * 0.2, e.y + e.height * 0.5, e.width * 0.2, e.height * 0.2);
          ctx.fillRect(e.x + e.width * 0.6, e.y + e.height * 0.5, e.width * 0.2, e.height * 0.2);

          // HP Bar for tank/boss
          if (e.maxHp > 20) {
              const hpPct = e.hp / e.maxHp;
              ctx.fillStyle = 'red';
              ctx.fillRect(e.x, e.y - 10, e.width, 4);
              ctx.fillStyle = 'green';
              ctx.fillRect(e.x, e.y - 10, e.width * hpPct, 4);
          }
      });

      // Draw Projectiles
      projectilesRef.current.forEach(p => {
          ctx.fillStyle = p.color;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.width/2, 0, Math.PI * 2);
          ctx.fill();
      });

      // Draw Particles
      particlesRef.current.forEach(p => {
          ctx.globalAlpha = p.life;
          ctx.fillStyle = p.color;
          ctx.fillRect(p.x, p.y, p.size, p.size);
          ctx.globalAlpha = 1.0;
      });

      // Draw Cursor Crosshair
      ctx.strokeStyle = '#22d3ee';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.arc(mouseRef.current.x, mouseRef.current.y, 8, 0, Math.PI * 2);
      ctx.moveTo(mouseRef.current.x - 12, mouseRef.current.y);
      ctx.lineTo(mouseRef.current.x + 12, mouseRef.current.y);
      ctx.moveTo(mouseRef.current.x, mouseRef.current.y - 12);
      ctx.lineTo(mouseRef.current.x, mouseRef.current.y + 12);
      ctx.stroke();

      animationFrameId = requestAnimationFrame(update);
    };

    animationFrameId = requestAnimationFrame(update);
    return () => cancelAnimationFrame(animationFrameId);
  }, [gameState, onGameOver, setLives, setScore, spawnWave, queueNextWave, setLevel]);

  return (
    <div className="relative rounded-lg overflow-hidden shadow-2xl border-2 border-slate-800 cursor-none">
      <canvas
        ref={canvasRef}
        width={CANVAS_WIDTH}
        height={CANVAS_HEIGHT}
        className="bg-black block w-full max-w-[800px] h-auto"
      />
      <div className="scanlines"></div>

      {/* Wave Loading Indicator */}
      {enemiesRef.current.length === 0 && gameState === GameState.PLAYING && (
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-green-400 font-mono text-xl animate-pulse pointer-events-none">
          SCANNING FOR HOSTILES...
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { GameCanvas } from './components/GameCanvas';
import { GameState } from './types';
import { GoogleGenAI } from '@google/genai';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0);
  const [lives, setLives] = useState(100);
  const [level, setLevel] = useState(1);
  const [flavorText, setFlavorText] = useState("System online. Waiting for pilot input.");
  const [highScore, setHighScore] = useState(0);

  const handleStartGame = () => {
    setGameState(GameState.PLAYING);
  };

  const handleGameOver = (finalScore: number) => {
    setGameState(GameState.GAME_OVER);
    if (finalScore > highScore) setHighScore(finalScore);
  };

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-4">
      {/* Header / HUD */}
      <div className="w-full max-w-[800px] flex justify-between items-end mb-4 font-mono">
        <div>
          <h1 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-blue-600">
            GEMINI STARFIGHTER
          </h1>
          <p className="text-slate-400 text-sm mt-1 h-6">{flavorText}</p>
        </div>
        <div className="text-right">
           <div className="text-sm text-slate-500">SCORE</div>
           <div className="text-2xl text-white font-bold tracking-widest">{score.toString().padStart(6, '0')}</div>
        </div>
      </div>

      {/* Main Game Container */}
      <div className="relative group">
        <GameCanvas 
          gameState={gameState}
          setGameState={setGameState}
          setScore={setScore}
          setLives={setLives}
          setLevel={setLevel}
          setFlavorText={setFlavorText}
          onGameOver={handleGameOver}
        />

        {/* Start Menu Overlay */}
        {gameState === GameState.MENU && (
          <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center z-20 backdrop-blur-sm">
            <h2 className="text-5xl font-bold text-white mb-8 tracking-tighter">READY PLAYER ONE</h2>
            <button 
              onClick={handleStartGame}
              className="px-8 py-4 bg-cyan-600 hover:bg-cyan-500 text-white font-bold rounded-none border-2 border-cyan-400 shadow-[0_0_20px_rgba(34,211,238,0.5)] transition-all transform hover:scale-105 active:scale-95 text-xl"
            >
              INITIATE LAUNCH
            </button>
            <p className="text-slate-500 mt-8 font-mono text-sm">
              WASD / ARROWS to Move • MOUSE to Aim & Shoot
            </p>
          </div>
        )}

        {/* Game Over Overlay */}
        {gameState === GameState.GAME_OVER && (
          <div className="absolute inset-0 bg-red-950/80 flex flex-col items-center justify-center text-center z-20 backdrop-blur-sm">
            <h2 className="text-5xl font-bold text-red-500 mb-2">MISSION FAILED</h2>
            <p className="text-xl text-white mb-6">FINAL SCORE: {score}</p>
            <button 
              onClick={handleStartGame}
              className="px-8 py-4 bg-red-600 hover:bg-red-500 text-white font-bold border-2 border-red-400 shadow-[0_0_20px_rgba(248,113,113,0.5)] transition-all transform hover:scale-105 active:scale-95"
            >
              RETRY MISSION
            </button>
          </div>
        )}

        {/* Pause Overlay */}
         {gameState === GameState.PAUSED && (
          <div className="absolute inset-0 bg-black/60 flex flex-col items-center justify-center text-center z-20 backdrop-blur-sm">
            <h2 className="text-4xl font-bold text-yellow-400 mb-8 tracking-widest">SYSTEM PAUSED</h2>
            <button 
              onClick={() => setGameState(GameState.PLAYING)}
              className="px-8 py-3 bg-yellow-600 hover:bg-yellow-500 text-white font-bold border-2 border-yellow-400 transition-all"
            >
              RESUME
            </button>
          </div>
        )}

        {/* HUD Overlay inside relative container */}
        {gameState === GameState.PLAYING && (
           <>
            {/* Health Bar */}
            <div className="absolute bottom-4 left-4 z-10 w-48">
              <div className="text-xs text-cyan-400 mb-1 font-mono">HULL INTEGRITY</div>
              <div className="h-4 bg-slate-800 border border-slate-600 w-full relative">
                <div 
                  className="h-full bg-gradient-to-r from-red-500 to-green-500 transition-all duration-300" 
                  style={{ width: `${Math.max(0, Math.min(100, lives))}%` }}
                ></div>
              </div>
            </div>

            {/* Level Indicator */}
            <div className="absolute bottom-4 right-4 z-10 text-right">
              <div className="text-xs text-cyan-400 mb-1 font-mono">THREAT LEVEL</div>
              <div className="text-2xl font-bold text-white font-mono">{level}</div>
            </div>
           </>
        )}
      </div>

      <div className="mt-8 text-slate-600 text-xs text-center font-mono max-w-lg">
        <p>Powered by Google Gemini AI</p>
        <p>Procedurally generated enemy waves based on tactical analysis.</p>
      </div>
    </div>
  );
};

export default App;

export enum GameState {
  MENU,
  PLAYING,
  PAUSED,
  GAME_OVER
}

export interface Point {
  x: number;
  y: number;
}

export interface Entity {
  id: number;
  x: number;
  y: number;
  width: number;
  height: number;
  color: string;
  vx: number;
  vy: number;
  markedForDeletion: boolean;
}

export interface Player extends Entity {
  hp: number;
  maxHp: number;
  weaponLevel: number;
  score: number;
  invulnerableUntil: number;
  rotation: number;
}

export interface Enemy extends Entity {
  hp: number;
  maxHp: number;
  type: 'scout' | 'fighter' | 'tank' | 'boss';
  scoreValue: number;
}

export interface Projectile extends Entity {
  damage: number;
  isEnemy: boolean;
}

export interface Particle extends Entity {
  life: number;
  maxLife: number;
  size: number;
}

export interface PowerUp extends Entity {
  type: 'weapon' | 'health';
  value: number;
}

export interface WaveConfig {
  enemies: {
    type: 'scout' | 'fighter' | 'tank' | 'boss';
    count: number;
    speed: number;
    hp: number;
    color: string;
  }[];
  flavorText: string;
}

export interface GameStats {
  score: number;
  level: number;
  enemiesDefeated: number;
}

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GameState, Player, Enemy, Projectile, Particle, WaveConfig, PowerUp } from '../types';
import { generateWave, fallbackWave } from '../services/geminiService';

interface GameCanvasProps {
  gameState: GameState;
  setGameState: (state: GameState) => void;
  setScore: (score: number) => void;
  setLives: (lives: number) => void;
  setLevel: (level: number) => void;
  setFlavorText: (text: string) => void;
  onGameOver: (finalScore: number) => void;
}

const CANVAS_WIDTH = 800;
const CANVAS_HEIGHT = 600;

export const GameCanvas: React.FC<GameCanvasProps> = ({
  gameState,
  setGameState,
  setScore,
  setLives,
  setLevel,
  setFlavorText,
  onGameOver
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Mutable game state refs
  const playerRef = useRef<Player>({
    id: 0, x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT - 100,
    width: 30, height: 30, color: '#3b82f6',
    vx: 0, vy: 0, markedForDeletion: false,
    hp: 100, maxHp: 100, weaponLevel: 1, score: 0, invulnerableUntil: 0,
    rotation: -Math.PI / 2 // Default facing up
  });

  const enemiesRef = useRef<Enemy[]>([]);
  const projectilesRef = useRef<Projectile[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const powerUpsRef = useRef<PowerUp[]>([]);
  const keysRef = useRef<{ [key: string]: boolean }>({});

  // Mouse state
  const mouseRef = useRef({ x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2 });
  const mouseDownRef = useRef(false);

  const levelRef = useRef(1);
  const wavePendingRef = useRef(false);
  const nextWaveConfigRef = useRef<WaveConfig | null>(null);

  // Initialize controls
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      keysRef.current[e.code] = true;
      if (e.code === 'Escape' && gameState === GameState.PLAYING) {
        setGameState(GameState.PAUSED);
      } else if (e.code === 'Escape' && gameState === GameState.PAUSED) {
        setGameState(GameState.PLAYING);
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      keysRef.current[e.code] = false;
    };

    const handleMouseMove = (e: MouseEvent) => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      // Calculate scale in case canvas is resized via CSS
      const scaleX = canvas.width / rect.width;
      const scaleY = canvas.height / rect.height;

      mouseRef.current = {
        x: (e.clientX - rect.left) * scaleX,
        y: (e.clientY - rect.top) * scaleY
      };
    };

    const handleMouseDown = (e: MouseEvent) => {
      if (e.button === 0) mouseDownRef.current = true;
    };

    const handleMouseUp = () => {
      mouseDownRef.current = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    // Bind mouse events to window to catch drags outside canvas, or canvas specifically if preferred. 
    // Using window for smoother aiming.
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [gameState, setGameState]);

  // Pre-fetch next wave
  const queueNextWave = useCallback(async () => {
    if (wavePendingRef.current) return;
    wavePendingRef.current = true;

    const healthPercent = Math.round((playerRef.current.hp / playerRef.current.maxHp) * 100);
    const context = `Player HP: ${healthPercent}%, Score: ${playerRef.current.score}, Weapon Level: ${playerRef.current.weaponLevel}. If HP is high, make it harder.`;

    try {
      const wave = await generateWave(levelRef.current + 1, context);
      nextWaveConfigRef.current = wave;
    } catch (e) {
      nextWaveConfigRef.current = fallbackWave;
    } finally {
      wavePendingRef.current = false;
    }
  }, []);

  // Spawn a wave
  const spawnWave = useCallback((config: WaveConfig) => {
    setFlavorText(config.flavorText);
    const newEnemies: Enemy[] = [];
    let idCounter = Date.now();

    config.enemies.forEach((group) => {
      for (let i = 0; i < group.count; i++) {
        newEnemies.push({
          id: idCounter++,
          x: Math.random() * (CANVAS_WIDTH - 60) + 30,
          y: -Math.random() * 200 - 50, 
          width: group.type === 'boss' ? 100 : (group.type === 'tank' ? 60 : 40),
          height: group.type === 'boss' ? 100 : (group.type === 'tank' ? 60 : 40),
          color: group.color,
          vx: (Math.random() - 0.5) * group.speed,
          vy: group.speed * 0.5,
          markedForDeletion: false,
          hp: group.hp,
          maxHp: group.hp,
          type: group.type,
          scoreValue: group.hp * 10
        });
      }
    });
    enemiesRef.current = [...enemiesRef.current, ...newEnemies];
  }, [setFlavorText]);

  // Reset Game
  const resetGame = useCallback(() => {
    playerRef.current = {
      id: 0, x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT - 100,
      width: 30, height: 30, color: '#3b82f6',
      vx: 0, vy: 0, markedForDeletion: false,
      hp: 100, maxHp: 100, weaponLevel: 1, score: 0, invulnerableUntil: 0,
      rotation: -Math.PI / 2
    };
    enemiesRef.current = [];
    projectilesRef.current = [];
    particlesRef.current = [];
    powerUpsRef.current = [];
    levelRef.current = 1;
    setScore(0);
    setLives(100);
    setLevel(1);

    spawnWave(fallbackWave);
    queueNextWave();
  }, [setScore, setLives, setLevel, queueNextWave, spawnWave]);

  useEffect(() => {
    if (gameState === GameState.PLAYING && enemiesRef.current.length === 0 && playerRef.current.score === 0) {
      resetGame();
    }
  }, [gameState, resetGame]);

  // Main Game Loop
  useEffect(() => {
    if (gameState !== GameState.PLAYING) return;

    let animationFrameId: number;
    let lastTime = performance.now();
    let fireCooldown = 0;

    const spawnParticle = (x: number, y: number, color: string, count: number = 5) => {
      for (let i = 0; i < count; i++) {
        particlesRef.current.push({
          id: Math.random(),
          x, y,
          width: 0, height: 0,
          vx: (Math.random() - 0.5) * 10,
          vy: (Math.random() - 0.5) * 10,
          color,
          life: 1.0,
          maxLife: 1.0,
          size: Math.random() * 4 + 2,
          markedForDeletion: false
        });
      }
    };

    const update = (time: number) => {
      const dt = (time - lastTime) / 1000;
      lastTime = time;

      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');

      if (!canvas || !ctx) return;

      // Clear canvas
      ctx.fillStyle = '#050505';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // --- PLAYER UPDATE ---
      const player = playerRef.current;
      const speed = 300;

      // Movement
      if (keysRef.current['ArrowLeft'] || keysRef.current['KeyA']) player.x -= speed * dt;
      if (keysRef.current['ArrowRight'] || keysRef.current['KeyD']) player.x += speed * dt;
      if (keysRef.current['ArrowUp'] || keysRef.current['KeyW']) player.y -= speed * dt;
      if (keysRef.current['ArrowDown'] || keysRef.current['KeyS']) player.y += speed * dt;

      // Clamp player
      player.x = Math.max(0, Math.min(CANVAS_WIDTH - player.width, player.x));
      player.y = Math.max(0, Math.min(CANVAS_HEIGHT - player.height, player.y));

      // Rotation (Aim at mouse)
      const centerX = player.x + player.width / 2;
      const centerY = player.y + player.height / 2;
      const dx = mouseRef.current.x - centerX;
      const dy = mouseRef.current.y - centerY;
      player.rotation = Math.atan2(dy, dx);

      // Shooting Logic
      if (mouseDownRef.current) {
        if (fireCooldown <= 0) {
          const gunLength = 25;
          const spawnX = centerX + Math.cos(player.rotation) * gunLength;
          const spawnY = centerY + Math.sin(player.rotation) * gunLength;

          // Base projectile stats
          const projSpeed = 800;
          const baseDamage = 10 + (player.weaponLevel * 2);

          // Function to add a projectile
          const addProj = (angleOffset: number, posOffsetMultiplier: number) => {
             // Perpendicular vector for parallel offset
             const perpX = Math.cos(player.rotation + Math.PI/2);
             const perpY = Math.sin(player.rotation + Math.PI/2);

             const angle = player.rotation + angleOffset;

             projectilesRef.current.push({
                id: Math.random(),
                x: spawnX + perpX * posOffsetMultiplier,
                y: spawnY + perpY * posOffsetMultiplier,
                width: 8, height: 8,
                color: player.weaponLevel >= 4 ? '#a855f7' : '#fbbf24', // Purple shots at high level
                vx: Math.cos(angle) * projSpeed,
                vy: Math.sin(angle) * projSpeed,
                markedForDeletion: false,
                damage: baseDamage,
                isEnemy: false
             });
          };

          // Weapon Patterns
          if (player.weaponLevel === 1) {
              addProj(0, 0);
              fireCooldown = 0.15;
          } else if (player.weaponLevel === 2) {
              // Dual shot parallel
              addProj(0, 6);
              addProj(0, -6);
              fireCooldown = 0.14;
          } else if (player.weaponLevel === 3) {
              // Triple shot spread
              addProj(0, 0);
              addProj(-0.1, 0);
              addProj(0.1, 0);
              fireCooldown = 0.13;
          } else if (player.weaponLevel >= 4) {
              // Quad shot spread + faster
              addProj(-0.05, 4);
              addProj(0.05, -4);
              addProj(-0.15, 8);
              addProj(0.15, -8);
              fireCooldown = 0.10; // Rapid fire
          }
        }
      }
      fireCooldown -= dt;

      // --- PROJECTILES ---
      projectilesRef.current.forEach(p => {
        p.x += p.vx * dt;
        p.y += p.vy * dt;
        if (p.x < -50 || p.x > CANVAS_WIDTH + 50 || p.y < -50 || p.y > CANVAS_HEIGHT + 50) {
          p.markedForDeletion = true;
        }
      });

      // --- POWERUPS ---
      powerUpsRef.current.forEach(p => {
          p.y += p.vy * dt;

          // Collision with player
          if (
              p.x < player.x + player.width &&
              p.x + p.width > player.x &&
              p.y < player.y + player.height &&
              p.y + p.height > player.y
          ) {
              p.markedForDeletion = true;
              spawnParticle(p.x + p.width/2, p.y + p.height/2, '#4ade80', 10);

              if (p.type === 'weapon') {
                  player.weaponLevel = Math.min(5, player.weaponLevel + 1);
                  setFlavorText(`WEAPON UPGRADED! LEVEL ${player.weaponLevel}`);
              } else if (p.type === 'health') {
                  player.hp = Math.min(player.maxHp, player.hp + 50);
                  setLives(player.hp);
                  setFlavorText("HULL REPAIRED");
              }
          }

          if (p.y > CANVAS_HEIGHT) p.markedForDeletion = true;
      });

      // --- ENEMIES ---
      if (enemiesRef.current.length === 0) {
         if (nextWaveConfigRef.current) {
             levelRef.current++;
             setLevel(levelRef.current);
             spawnWave(nextWaveConfigRef.current);
             nextWaveConfigRef.current = null;
             queueNextWave();
         } else if (!wavePendingRef.current) {
             queueNextWave();
         }
      }

      enemiesRef.current.forEach(enemy => {
        enemy.y += enemy.vy * 60 * dt; 
        enemy.x += Math.sin(time / 500 + enemy.id) * 2; 

        if (enemy.y > CANVAS_HEIGHT) {
          enemy.markedForDeletion = true;
          player.score = Math.max(0, player.score - 50); 
        }

        // Enemy Shooting
        if (Math.random() < 0.005 * (levelRef.current * 0.5)) {
           const ex = enemy.x + enemy.width/2;
           const ey = enemy.y + enemy.height;
           const angleToPlayer = Math.atan2(player.y - ey, player.x - ex);

           const isSmart = levelRef.current > 2 && Math.random() > 0.5;
           const vx = isSmart ? Math.cos(angleToPlayer) * 300 : 0;
           const vy = isSmart ? Math.sin(angleToPlayer) * 300 : 300;

           projectilesRef.current.push({
            id: Math.random(),
            x: ex,
            y: ey,
            width: 6, height: 6,
            color: '#ef4444',
            vx: vx, vy: vy,
            markedForDeletion: false,
            damage: 10,
            isEnemy: true
          });
        }
      });

      // --- COLLISION ---
      projectilesRef.current.forEach(proj => {
        if (proj.markedForDeletion) return;

        if (proj.isEnemy) {
            // Hit Player
            if (
                proj.x < player.x + player.width &&
                proj.x + proj.width > player.x &&
                proj.y < player.y + player.height &&
                proj.y + proj.height > player.y
            ) {
                 if (Date.now() > player.invulnerableUntil) {
                     player.hp -= proj.damage;
                     proj.markedForDeletion = true;
                     spawnParticle(player.x + player.width/2, player.y + player.height/2, '#ef4444', 10);
                     if (player.hp <= 0) {
                         onGameOver(player.score);
                     }
                     setLives(player.hp);
                 }
            }
        } else {
            // Hit Enemy
            enemiesRef.current.forEach(enemy => {
                if (
                    proj.x < enemy.x + enemy.width &&
                    proj.x + proj.width > enemy.x &&
                    proj.y < enemy.y + enemy.height &&
                    proj.y + proj.height > enemy.y
                ) {
                    enemy.hp -= proj.damage;
                    proj.markedForDeletion = true;
                    spawnParticle(proj.x, proj.y, '#fbbf24', 3);

                    if (enemy.hp <= 0) {
                        enemy.markedForDeletion = true;
                        player.score += enemy.scoreValue;
                        spawnParticle(enemy.x + enemy.width/2, enemy.y + enemy.height/2, enemy.color, 15);

                        // Drop PowerUp Chance
                        if (Math.random() < 0.15) { // 15% chance
                            const isWeapon = Math.random() > 0.3; // 70% weapon, 30% health
                            powerUpsRef.current.push({
                                id: Math.random(),
                                x: enemy.x + enemy.width/2 - 10,
                                y: enemy.y + enemy.height/2 - 10,
                                width: 20, height: 20,
                                color: isWeapon ? '#4ade80' : '#f43f5e',
                                vx: 0, vy: 60, // drifts down slowly
                                markedForDeletion: false,
                                type: isWeapon ? 'weapon' : 'health',
                                value: 1
                            });
                        }
                    }
                }
            });
        }
      });

      setScore(player.score);

      // --- PARTICLES ---
      particlesRef.current.forEach(p => {
        p.x += p.vx;
        p.y += p.vy;
        p.life -= dt * 2;
        if (p.life <= 0) p.markedForDeletion = true;
      });

      // Cleanup
      enemiesRef.current = enemiesRef.current.filter(e => !e.markedForDeletion);
      projectilesRef.current = projectilesRef.current.filter(p => !p.markedForDeletion);
      particlesRef.current = particlesRef.current.filter(p => !p.markedForDeletion);
      powerUpsRef.current = powerUpsRef.current.filter(p => !p.markedForDeletion);

      // --- DRAWING ---

      // Draw PowerUps
      powerUpsRef.current.forEach(p => {
          ctx.fillStyle = p.color;
          ctx.fillRect(p.x, p.y, p.width, p.height);
          // Border
          ctx.strokeStyle = 'white';
          ctx.lineWidth = 1;
          ctx.strokeRect(p.x, p.y, p.width, p.height);
          // Symbol
          ctx.fillStyle = 'white';
          ctx.font = '14px monospace';
          ctx.fillText(p.type === 'weapon' ? 'W' : 'H', p.x + 4, p.y + 15);
      });

      // Draw Player (Rotated)
      if (player.hp > 0) {
          ctx.save();
          const cx = player.x + player.width / 2;
          const cy = player.y + player.height / 2;
          ctx.translate(cx, cy);
          ctx.rotate(player.rotation);

          // Body (Circle)
          ctx.fillStyle = player.color;
          ctx.beginPath();
          ctx.arc(0, 0, player.width / 2, 0, Math.PI * 2);
          ctx.fill();

          // Gun Visual changes based on level
          ctx.fillStyle = '#1e3a8a'; 
          if (player.weaponLevel === 1) {
             ctx.fillRect(0, -4, 25, 8); 
          } else if (player.weaponLevel === 2) {
             ctx.fillRect(0, -6, 25, 4); 
             ctx.fillRect(0, 2, 25, 4); 
          } else {
             ctx.fillRect(0, -4, 28, 8); 
             ctx.fillStyle = '#60a5fa';
             ctx.fillRect(5, -8, 20, 16); 
          }

          // Shoulders/Armor detail
          ctx.fillStyle = '#60a5fa';
          ctx.fillRect(-10, -12, 10, 24); // Backpack/Armor

          // Helmet Visor
          ctx.fillStyle = '#bfdbfe';
          ctx.beginPath();
          ctx.arc(4, 0, 6, -Math.PI/4, Math.PI/4);
          ctx.fill();

          ctx.restore();
      }

      // Draw Enemies
      enemiesRef.current.forEach(e => {
          ctx.fillStyle = e.color;
          ctx.fillRect(e.x, e.y, e.width, e.height);

          ctx.fillStyle = 'rgba(0,0,0,0.3)';
          ctx.fillRect(e.x + e.width * 0.2, e.y + e.height * 0.5, e.width * 0.2, e.height * 0.2);
          ctx.fillRect(e.x + e.width * 0.6, e.y + e.height * 0.5, e.width * 0.2, e.height * 0.2);

          // HP Bar for tank/boss
          if (e.maxHp > 20) {
              const hpPct = e.hp / e.maxHp;
              ctx.fillStyle = 'red';
              ctx.fillRect(e.x, e.y - 10, e.width, 4);
              ctx.fillStyle = 'green';
              ctx.fillRect(e.x, e.y - 10, e.width * hpPct, 4);
          }
      });

      // Draw Projectiles
      projectilesRef.current.forEach(p => {
          ctx.fillStyle = p.color;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.width/2, 0, Math.PI * 2);
          ctx.fill();
      });

      // Draw Particles
      particlesRef.current.forEach(p => {
          ctx.globalAlpha = p.life;
          ctx.fillStyle = p.color;
          ctx.fillRect(p.x, p.y, p.size, p.size);
          ctx.globalAlpha = 1.0;
      });

      // Draw Cursor Crosshair
      ctx.strokeStyle = '#22d3ee';
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.arc(mouseRef.current.x, mouseRef.current.y, 8, 0, Math.PI * 2);
      ctx.moveTo(mouseRef.current.x - 12, mouseRef.current.y);
      ctx.lineTo(mouseRef.current.x + 12, mouseRef.current.y);
      ctx.moveTo(mouseRef.current.x, mouseRef.current.y - 12);
      ctx.lineTo(mouseRef.current.x, mouseRef.current.y + 12);
      ctx.stroke();

      animationFrameId = requestAnimationFrame(update);
    };

    animationFrameId = requestAnimationFrame(update);
    return () => cancelAnimationFrame(animationFrameId);
  }, [gameState, onGameOver, setLives, setScore, spawnWave, queueNextWave, setLevel]);

  return (
    <div className="relative rounded-lg overflow-hidden shadow-2xl border-2 border-slate-800 cursor-none">
      <canvas
        ref={canvasRef}
        width={CANVAS_WIDTH}
        height={CANVAS_HEIGHT}
        className="bg-black block w-full max-w-[800px] h-auto"
      />
      <div className="scanlines"></div>

      {/* Wave Loading Indicator */}
      {enemiesRef.current.length === 0 && gameState === GameState.PLAYING && (
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-green-400 font-mono text-xl animate-pulse pointer-events-none">
          SCANNING FOR HOSTILES...
        </div>
      )}
    </div>
  );
};

