import React, { useState } from 'react';
import { GameCanvas } from './components/GameCanvas';
import { GameState } from './types';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0);
  const [lives, setLives] = useState(100);
  const [level, setLevel] = useState(1);
  const [flavorText, setFlavorText] = useState("System online. Waiting for pilot input.");
  const [highScore, setHighScore] = useState(0);

  const handleStartGame = () => {
    setGameState(GameState.PLAYING);
  };

  const handleGameOver = (finalScore: number) => {
    setGameState(GameState.GAME_OVER);
    if (finalScore > highScore) setHighScore(finalScore);
  };

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-4">
      {/* Header / HUD */}
      <div className="w-full max-w-[800px] flex justify-between items-end mb-4 font-mono">
        <div>
          <h1 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-blue-600">
            GEMINI STARFIGHTER
          </h1>
          <p className="text-slate-400 text-sm mt-1 h-6">{flavorText}</p>
        </div>
        <div className="text-right">
           <div className="text-sm text-slate-500">SCORE</div>
           <div className="text-2xl text-white font-bold tracking-widest">{score.toString().padStart(6, '0')}</div>
        </div>
      </div>

      {/* Main Game Container */}
      <div className="relative group">
        <GameCanvas 
          gameState={gameState}
          setGameState={setGameState}
          setScore={setScore}
          setLives={setLives}
          setLevel={setLevel}
          setFlavorText={setFlavorText}
          onGameOver={handleGameOver}
        />

        {/* Start Menu Overlay */}
        {gameState === GameState.MENU && (
          <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center z-20 backdrop-blur-sm">
            <h2 className="text-5xl font-bold text-white mb-8 tracking-tighter">READY PLAYER ONE</h2>
            <button 
              onClick={handleStartGame}
              className="px-8 py-4 bg-cyan-600 hover:bg-cyan-500 text-white font-bold rounded-none border-2 border-cyan-400 shadow-[0_0_20px_rgba(34,211,238,0.5)] transition-all transform hover:scale-105 active:scale-95 text-xl"
            >
              INITIATE LAUNCH
