        {gameState === GameState.PLAYING && (
           <>
            {/* Health Bar */}
            <div className="absolute bottom-4 left-4 z-10 w-48">
              <div className="text-xs text-cyan-400 mb-1 font-mono">HULL INTEGRITY</div>
              <div className="h-4 bg-slate-800 border border-slate-600 w-full relative">
