      </div>

      <div className="mt-8 text-slate-600 text-xs text-center font-mono max-w-lg">
        <p>Powered by Google Gemini AI</p>
        <p>Procedurally generated enemy waves based on tactical analysis.</p>
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { WaveConfig } from "../types";

// Helper to safely access environment variables in different build environments (Vite, Next.js, etc.)
const getApiKey = () => {
  // Vite exposes env vars via import.meta.env
  if (typeof import.meta !== 'undefined' && import.meta.env) {
    return import.meta.env.VITE_API_KEY || import.meta.env.API_KEY;
  }
  // Standard process.env fallback (safely accessed)
  if (typeof process !== 'undefined' && process.env) {
    return process.env.NEXT_PUBLIC_API_KEY || process.env.REACT_APP_API_KEY || process.env.API_KEY;
  }
  return '';
};

const ai = new GoogleGenAI({ apiKey: getApiKey() });

const modelName = 'gemini-2.5-flash';

// Fallback wave if API fails or for first level
export const fallbackWave: WaveConfig = {
  enemies: [
    { type: 'scout', count: 5, speed: 2, hp: 10, color: '#34d399' },
    { type: 'fighter', count: 2, speed: 1.5, hp: 30, color: '#60a5fa' }
  ],
  flavorText: "System initialized. Engaging standard defense protocols."
};

export const generateWave = async (level: number, playerPerformance: string): Promise<WaveConfig> => {
  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: `
        Generate a wave of enemies for a space shooter game.
        Current Level: ${level}.
        Player Performance Context: ${playerPerformance}.

        Rules:
        - As level increases, enemies should get harder (more HP, speed, or count).
        - 'scout' are fast/weak, 'fighter' are balanced, 'tank' are slow/tough, 'boss' is very strong (only 1 per wave usually).
        - Colors should be hex codes valid in CSS.
        - Provide a short, sci-fi military style flavor text describing the incoming threat.
        - Enemy count should be reasonable (total 5-20 usually).
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            enemies: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING, enum: ['scout', 'fighter', 'tank', 'boss'] },
                  count: { type: Type.NUMBER },
                  speed: { type: Type.NUMBER },
                  hp: { type: Type.NUMBER },
                  color: { type: Type.STRING }
                },
                required: ['type', 'count', 'speed', 'hp', 'color']
              }
            },
            flavorText: { type: Type.STRING }
          },
          required: ['enemies', 'flavorText']
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as WaveConfig;
    }
    return fallbackWave;
  } catch (error) {
    console.error("Gemini generation failed (check API Key):", error);
    return fallbackWave;
  }
};

