export enum GameState {
  MENU,
  PLAYING,
  PAUSED,
  GAME_OVER
}

export interface Point {
  x: number;
  y: number;
}

export interface Entity {
  id: number;
  x: number;
  y: number;
  width: number;
  height: number;
  color: string;
  vx: number;
  vy: number;
  markedForDeletion: boolean;
}

export interface Player extends Entity {
  hp: number;
  maxHp: number;
  weaponLevel: number;
  score: number;
  invulnerableUntil: number;
  rotation: number;
}

export interface Enemy extends Entity {
  hp: number;
  maxHp: number;
  type: 'scout' | 'fighter' | 'tank' | 'boss' | 'turret' | 'kamikaze';
  scoreValue: number;
}

export interface Projectile extends Entity {
  damage: number;
  isEnemy: boolean;
}

export interface Particle extends Entity {
  life: number;
  maxLife: number;
  size: number;
}

export interface PowerUp extends Entity {
  type: 'weapon' | 'health';
  value: number;
}

export interface WaveConfig {
  enemies: {
    type: 'scout' | 'fighter' | 'tank' | 'boss' | 'turret' | 'kamikaze';
    count: number;
    speed: number;
    hp: number;
    color: string;
  }[];
  flavorText: string;
}

export interface GameStats {
  score: number;
  level: number;
  enemiesDefeated: number;
}

