const supabaseUrl = 'https://occqvxiaxafrplyszzdy.supabase.co';
const supabaseKey = 'sb_publishable_UWC1srUuuwrw4c8k7U9LPA_I--GEjTD';

export const supabase = createClient(supabaseUrl, supabaseKey);

export const fetchLeaderboard = async (): Promise<LeaderboardEntry[]> => {
  try {
    const { data, error } = await supabase
      .from('leaderboard')
      .select('*')
      .order('score', { ascending: false })
      .limit(10);

    if (error) {
      console.error('Error fetching leaderboard:', error);
      return [];
    }
    return data as LeaderboardEntry[];
  } catch (err) {
    console.error('Supabase connection error:', err);
    return [];
  }
};

export const submitScore = async (username: string, score: number, level: number) => {
  try {
    const { error } = await supabase
      .from('leaderboard')
      .insert([
        { username, score, level }
      ]);

    if (error) {
      console.error('Error submitting score:', error);
      return false;
    }
    return true;
  } catch (err) {
    console.error('Supabase submission error:', err);
    return false;
  }
};

import React, { useState, useEffect } from 'react';
import { GameCanvas } from './components/GameCanvas';
import { GameState, LeaderboardEntry } from './types';
import { fetchLeaderboard, submitScore } from './services/supabaseClient';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0);
  const [lives, setLives] = useState(100);
  const [level, setLevel] = useState(1);
  const [flavorText, setFlavorText] = useState("System online. Waiting for pilot input.");
  const [highScore, setHighScore] = useState(0);

  // Leaderboard State
  const [leaderboard, setLeaderboard] = useState<LeaderboardEntry[]>([]);
  const [pilotName, setPilotName] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submissionSuccess, setSubmissionSuccess] = useState(false);

  useEffect(() => {
    // Load leaderboard on mount
    loadLeaderboard();
  }, []);

  const loadLeaderboard = async () => {
    const data = await fetchLeaderboard();
    setLeaderboard(data);
  };

  const handleStartGame = () => {
    setGameState(GameState.PLAYING);
    setSubmissionSuccess(false);
    setPilotName("");
  };

  const handleGameOver = (finalScore: number) => {
    setGameState(GameState.GAME_OVER);
    if (finalScore > highScore) setHighScore(finalScore);
  };

  const handleSubmitScore = async () => {
    if (!pilotName.trim()) return;
    setIsSubmitting(true);
    const success = await submitScore(pilotName.toUpperCase(), score, level);
    if (success) {
      setSubmissionSuccess(true);
      await loadLeaderboard(); // Refresh list
    }
    setIsSubmitting(false);
  };

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-4">
      {/* Header / HUD */}
      <div className="w-full max-w-[800px] flex justify-between items-end mb-4 font-mono">
        <div>
          <h1 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-blue-600">
            GEMINI STARFIGHTER
          </h1>
          <p className="text-slate-400 text-sm mt-1 h-6">{flavorText}</p>
        </div>
        <div className="text-right">
           <div className="text-sm text-slate-500">SCORE</div>
           <div className="text-2xl text-white font-bold tracking-widest">{score.toString().padStart(6, '0')}</div>
        </div>
      </div>

      {/* Main Game Container */}
      <div className="relative group">
        <GameCanvas 
          gameState={gameState}
          setGameState={setGameState}
          setScore={setScore}
          setLives={setLives}
          setLevel={setLevel}
          setFlavorText={setFlavorText}
          onGameOver={handleGameOver}
        />

        {/* Start Menu Overlay */}
        {gameState === GameState.MENU && (
          <div className="absolute inset-0 bg-black/90 flex flex-row items-stretch justify-center z-20 backdrop-blur-sm overflow-hidden">
            {/* Left: Menu */}
            <div className="flex-1 flex flex-col items-center justify-center p-8 border-r border-slate-800">
                <h2 className="text-5xl font-bold text-white mb-8 tracking-tighter">READY PLAYER ONE</h2>
                <button 
                  onClick={handleStartGame}
                  className="px-8 py-4 bg-cyan-600 hover:bg-cyan-500 text-white font-bold rounded-none border-2 border-cyan-400 shadow-[0_0_20px_rgba(34,211,238,0.5)] transition-all transform hover:scale-105 active:scale-95 text-xl"
                >
                  INITIATE LAUNCH
                </button>
                <p className="text-slate-500 mt-8 font-mono text-sm">
                  WASD / ARROWS to Move • MOUSE to Aim & Shoot
                </p>
            </div>

            {/* Right: Leaderboard */}
            <div className="w-64 bg-slate-900/50 p-6 flex flex-col border-l border-slate-800">
                <h3 className="text-cyan-400 font-bold mb-4 tracking-widest text-center border-b border-cyan-900 pb-2">TOP ACES</h3>
                <div className="flex-1 overflow-y-auto space-y-2 no-scrollbar">
                    {leaderboard.length === 0 ? (
                        <p className="text-xs text-slate-600 text-center mt-4">NO DATA FOUND</p>
                    ) : (
                        leaderboard.map((entry, idx) => (
                            <div key={entry.id} className="flex justify-between items-center text-xs font-mono">
                                <span className={`mr-2 ${idx < 3 ? 'text-yellow-400 font-bold' : 'text-slate-400'}`}>
                                    {idx + 1}. {entry.username}
                                </span>
                                <span className="text-white">{entry.score}</span>
                            </div>
                        ))
                    )}
                </div>
            </div>
          </div>
        )}

        {/* Game Over Overlay */}
        {gameState === GameState.GAME_OVER && (
          <div className="absolute inset-0 bg-red-950/90 flex flex-col items-center justify-center text-center z-20 backdrop-blur-sm p-8">
            <h2 className="text-5xl font-bold text-red-500 mb-2">MISSION FAILED</h2>
            <p className="text-xl text-white mb-8">FINAL SCORE: {score}</p>

            {!submissionSuccess ? (
                <div className="bg-black/50 p-6 border border-red-900 mb-8 w-full max-w-sm">
                    <p className="text-red-400 text-sm mb-2 font-mono">ENTER PILOT IDENTIFICATION</p>
                    <div className="flex gap-2">
                        <input 
                            type="text" 
                            maxLength={8}
                            value={pilotName}
                            onChange={(e) => setPilotName(e.target.value.toUpperCase())}
                            placeholder="NAME"
                            className="bg-red-950/50 border border-red-800 text-white px-4 py-2 w-full font-mono focus:outline-none focus:border-red-500"
                        />
                        <button 
                            onClick={handleSubmitScore}
                            disabled={isSubmitting || !pilotName}
                            className="bg-red-600 hover:bg-red-500 text-white px-4 py-2 font-bold disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            {isSubmitting ? '...' : 'SAVE'}
                        </button>
                    </div>
                </div>
            ) : (
                <div className="mb-8 text-green-400 font-mono border border-green-900 bg-green-950/30 px-6 py-4">
                    FLIGHT DATA UPLOADED SUCCESSFULLY
                </div>
            )}

            <button 
              onClick={handleStartGame}
              className="px-8 py-4 bg-transparent hover:bg-red-900/50 text-white font-bold border-2 border-red-400 shadow-[0_0_20px_rgba(248,113,113,0.5)] transition-all transform hover:scale-105 active:scale-95"
            >
              RETRY MISSION
            </button>
          </div>
        )}

        {/* Pause Overlay */}
         {gameState === GameState.PAUSED && (
          <div className="absolute inset-0 bg-black/60 flex flex-col items-center justify-center text-center z-20 backdrop-blur-sm">
            <h2 className="text-4xl font-bold text-yellow-400 mb-8 tracking-widest">SYSTEM PAUSED</h2>
            <button 
              onClick={() => setGameState(GameState.PLAYING)}
              className="px-8 py-3 bg-yellow-600 hover:bg-yellow-500 text-white font-bold border-2 border-yellow-400 transition-all"
            >
              RESUME
            </button>
          </div>
        )}

        {/* HUD Overlay inside relative container */}
        {gameState === GameState.PLAYING && (
           <>
            {/* Health Bar */}
            <div className="absolute bottom-4 left-4 z-10 w-48">
              <div className="text-xs text-cyan-400 mb-1 font-mono">HULL INTEGRITY</div>
              <div className="h-4 bg-slate-800 border border-slate-600 w-full relative">
                <div 
                  className="h-full bg-gradient-to-r from-red-500 to-green-500 transition-all duration-300" 
                  style={{ width: `${Math.max(0, Math.min(100, lives))}%` }}
                ></div>
              </div>
            </div>

            {/* Level Indicator */}
            <div className="absolute bottom-4 right-4 z-10 text-right">
              <div className="text-xs text-cyan-400 mb-1 font-mono">THREAT LEVEL</div>
              <div className="text-2xl font-bold text-white font-mono">{level}</div>
            </div>
           </>
        )}
      </div>

      <div className="mt-8 text-slate-600 text-xs text-center font-mono max-w-lg">
        <p>Powered by Google Gemini AI</p>
        <p>Procedurally generated enemy waves based on tactical analysis.</p>
      </div>
    </div>
  );
};

