import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GameState, Player, Enemy, Projectile, Particle, WaveConfig, PowerUp, UpgradeOption } from '../types';
import { generateWave, fallbackWave } from '../services/geminiService';

interface GameCanvasProps {
  gameState: GameState;
  setGameState: (state: GameState) => void;
  setScore: (score: number) => void;
  setLives: (lives: number) => void;
  setLevel: (level: number) => void;
  setFlavorText: (text: string) => void;
  onGameOver: (finalScore: number) => void;
}

const CANVAS_WIDTH = 800;
const CANVAS_HEIGHT = 600;

export const GameCanvas: React.FC<GameCanvasProps> = ({
  gameState,
  setGameState,
  setScore,
  setLives,
  setLevel,
  setFlavorText,
  onGameOver
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Mutable game state refs
  const playerRef = useRef<Player>({
    id: 0, x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT - 100,
    width: 30, height: 30, color: '#3b82f6',
    vx: 0, vy: 0, markedForDeletion: false,
    hp: 100, maxHp: 100, weaponLevel: 1, score: 0, credits: 0, invulnerableUntil: 0,
    rotation: -Math.PI / 2,
    gunType: 'blaster',
    moveSpeed: 300
  });

  const enemiesRef = useRef<Enemy[]>([]);
  const projectilesRef = useRef<Projectile[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const powerUpsRef = useRef<PowerUp[]>([]);
  const keysRef = useRef<{ [key: string]: boolean }>({});

  // Mouse state
  const mouseRef = useRef({ x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2 });
  const mouseDownRef = useRef(false);

  // Joystick state for mobile
  const leftStick = useRef({ active: false, id: -1, originX: 0, originY: 0, currX: 0, currY: 0, valX: 0, valY: 0 });
  const rightStick = useRef({ active: false, id: -1, originX: 0, originY: 0, currX: 0, currY: 0, valX: 0, valY: 0 });

  const levelRef = useRef(1);
  const wavePendingRef = useRef(false);
  const nextWaveConfigRef = useRef<WaveConfig | null>(null);

  // Shop State
  const [shopOpen, setShopOpen] = useState(false);
  const [shopItems, setShopItems] = useState<UpgradeOption[]>([]);
  const [currentCredits, setCurrentCredits] = useState(0);

  // Initialize controls
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      keysRef.current[e.code] = true;
      if (e.code === 'Escape' && gameState === GameState.PLAYING && !shopOpen) {
        setGameState(GameState.PAUSED);
      } else if (e.code === 'Escape' && gameState === GameState.PAUSED) {
        setGameState(GameState.PLAYING);
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      keysRef.current[e.code] = false;
    };

    const handleMouseMove = (e: MouseEvent) => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      const scaleX = canvas.width / rect.width;
      const scaleY = canvas.height / rect.height;

      mouseRef.current = {
        x: (e.clientX - rect.left) * scaleX,
        y: (e.clientY - rect.top) * scaleY
      };
    };

    const handleMouseDown = (e: MouseEvent) => {
      if (e.button === 0) mouseDownRef.current = true;
    };

    const handleMouseUp = () => {
      mouseDownRef.current = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [gameState, setGameState, shopOpen]);

  // Touch Handlers
  const handleTouchStart = (e: React.TouchEvent) => {
    e.preventDefault(); // Prevent scrolling
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    const scaleX = CANVAS_WIDTH / rect.width;
    const scaleY = CANVAS_HEIGHT / rect.height;

    Array.from(e.changedTouches).forEach(touch => {
      const x = (touch.clientX - rect.left) * scaleX;
      const y = (touch.clientY - rect.top) * scaleY;

      if (x < CANVAS_WIDTH / 2) {
        // Left Stick (Move)
        if (!leftStick.current.active) {
            leftStick.current = { active: true, id: touch.identifier, originX: x, originY: y, currX: x, currY: y, valX: 0, valY: 0 };
        }
      } else {
        // Right Stick (Aim/Shoot)
        if (!rightStick.current.active) {
            rightStick.current = { active: true, id: touch.identifier, originX: x, originY: y, currX: x, currY: y, valX: 0, valY: 0 };
            mouseDownRef.current = true; // Auto-fire on mobile aim
        }
      }
    });
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    e.preventDefault();
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    const scaleX = CANVAS_WIDTH / rect.width;
    const scaleY = CANVAS_HEIGHT / rect.height;

    Array.from(e.changedTouches).forEach(touch => {
       const x = (touch.clientX - rect.left) * scaleX;
       const y = (touch.clientY - rect.top) * scaleY;
       const maxDist = 50; // Max radius of joystick

       if (leftStick.current.active && leftStick.current.id === touch.identifier) {
          leftStick.current.currX = x;
          leftStick.current.currY = y;
          let dx = x - leftStick.current.originX;
          let dy = y - leftStick.current.originY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist > maxDist) {
             dx = (dx / dist) * maxDist;
             dy = (dy / dist) * maxDist;
             leftStick.current.currX = leftStick.current.originX + dx;
             leftStick.current.currY = leftStick.current.originY + dy;
          }
          leftStick.current.valX = dx / maxDist;
          leftStick.current.valY = dy / maxDist;
       }

       if (rightStick.current.active && rightStick.current.id === touch.identifier) {
          rightStick.current.currX = x;
          rightStick.current.currY = y;
          let dx = x - rightStick.current.originX;
          let dy = y - rightStick.current.originY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist > maxDist) {
             dx = (dx / dist) * maxDist;
             dy = (dy / dist) * maxDist;
             rightStick.current.currX = rightStick.current.originX + dx;
             rightStick.current.currY = rightStick.current.originY + dy;
          }
          rightStick.current.valX = dx / maxDist;
          rightStick.current.valY = dy / maxDist;
       }
    });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    e.preventDefault();
    Array.from(e.changedTouches).forEach(touch => {
       if (leftStick.current.active && leftStick.current.id === touch.identifier) {
          leftStick.current.active = false;
          leftStick.current.valX = 0;
          leftStick.current.valY = 0;
       }
       if (rightStick.current.active && rightStick.current.id === touch.identifier) {
          rightStick.current.active = false;
          mouseDownRef.current = false;
       }
    });
  };

  // Generate Shop Items
  const generateShopItems = useCallback(() => {
    const player = playerRef.current;

    const allUpgrades: UpgradeOption[] = [
      {
        id: 'repair',
        title: 'HULL PATCH',
        description: 'Repair 50 HP',
        type: 'heal',
        cost: 100,
        color: '#4ade80',
        apply: (p) => { p.hp = Math.min(p.maxHp, p.hp + 50); setLives(p.hp); }
      },
      {
        id: 'maxhp',
        title: 'TITANIUM PLATING',
        description: '+50 Max HP',
        type: 'stat',
        cost: 300,
        color: '#10b981',
        apply: (p) => { p.maxHp += 50; p.hp += 50; setLives(p.hp); }
      },
      {
        id: 'speed',
        title: 'NITRO INJECTOR',
        description: '+10% Speed',
        type: 'stat',
        cost: 200,
        color: '#06b6d4',
        apply: (p) => { p.moveSpeed *= 1.1; }
      },
      {
        id: 'weapon_power',
        title: 'CORE OVERCLOCK',
        description: '+1 Weapon Level',
        type: 'stat',
        cost: 500 * player.weaponLevel,
        color: '#f59e0b',
        apply: (p) => { p.weaponLevel += 1; }
      }
    ];

    // Gun swaps (Expensive)
    if (player.gunType !== 'blaster') {
      allUpgrades.push({
        id: 'gun_blaster',
        title: 'PULSE RIFLE',
        description: 'Balanced rapid fire.',
        type: 'gun',
        cost: 800,
        color: '#3b82f6',
        apply: (p) => { p.gunType = 'blaster'; }
      });
    }
    if (player.gunType !== 'spread') {
      allUpgrades.push({
        id: 'gun_spread',
        title: 'FLAK CANNON',
        description: 'Wide spread shot.',
        type: 'gun',
        cost: 1200,
        color: '#8b5cf6',
        apply: (p) => { p.gunType = 'spread'; }
      });
    }
    if (player.gunType !== 'plasma') {
      allUpgrades.push({
        id: 'gun_plasma',
        title: 'PLASMA CASTER',
        description: 'High damage bolts.',
        type: 'gun',
        cost: 1500,
        color: '#ef4444',
        apply: (p) => { p.gunType = 'plasma'; }
      });
    }

    // Select 4 random items
    const shuffled = allUpgrades.sort(() => 0.5 - Math.random());
    setShopItems(shuffled.slice(0, 4));
    setCurrentCredits(player.credits);
  }, [setLives]);

  // Pre-fetch next wave
  const queueNextWave = useCallback(async () => {
    if (wavePendingRef.current) return;
    wavePendingRef.current = true;

    const healthPercent = Math.round((playerRef.current.hp / playerRef.current.maxHp) * 100);
    const context = `Player HP: ${healthPercent}%, Gun: ${playerRef.current.gunType}, Weapon Level: ${playerRef.current.weaponLevel}.`;

    try {
      const wave = await generateWave(levelRef.current + 1, context);
      nextWaveConfigRef.current = wave;
    } catch (e) {
      nextWaveConfigRef.current = fallbackWave;
    } finally {
      wavePendingRef.current = false;
    }
  }, []);

  // Spawn a wave
  const spawnWave = useCallback((config: WaveConfig) => {
    setFlavorText(config.flavorText);
    const newEnemies: Enemy[] = [];
    let idCounter = Date.now();

    config.enemies.forEach((group) => {
      for (let i = 0; i < group.count; i++) {
        let w = 40, h = 40;
        if (group.type === 'boss') { w = 100; h = 100; }
        else if (group.type === 'tank' || group.type === 'turret') { w = 60; h = 60; }
        else if (group.type === 'kamikaze') { w = 25; h = 25; }

        newEnemies.push({
          id: idCounter++,
          x: Math.random() * (CANVAS_WIDTH - 60) + 30,
          y: -Math.random() * 200 - 50, 
          width: w,
          height: h,
          color: group.color,
          vx: (Math.random() - 0.5) * group.speed,
          vy: group.speed * 0.5,
          markedForDeletion: false,
          hp: group.hp,
          maxHp: group.hp,
          type: group.type,
          scoreValue: group.hp * 10,
          creditsValue: Math.max(10, Math.floor(group.hp * 1.5))
        });
      }
    });
    enemiesRef.current = [...enemiesRef.current, ...newEnemies];
  }, [setFlavorText]);

  // Reset Game
  const resetGame = useCallback(() => {
    playerRef.current = {
      id: 0, x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT - 100,
      width: 30, height: 30, color: '#3b82f6',
      vx: 0, vy: 0, markedForDeletion: false,
      hp: 100, maxHp: 100, weaponLevel: 1, score: 0, credits: 0, invulnerableUntil: 0,
      rotation: -Math.PI / 2,
      gunType: 'blaster',
      moveSpeed: 300
    };
    enemiesRef.current = [];
    projectilesRef.current = [];
    particlesRef.current = [];
    powerUpsRef.current = [];
    levelRef.current = 1;
    setScore(0);
    setLives(100);
    setLevel(1);
    setShopOpen(false);

    // Reset sticks
    leftStick.current.active = false;
    rightStick.current.active = false;
    mouseDownRef.current = false;

    spawnWave(fallbackWave);
    queueNextWave();
  }, [setScore, setLives, setLevel, queueNextWave, spawnWave]);

  useEffect(() => {
    if (gameState === GameState.PLAYING && enemiesRef.current.length === 0 && playerRef.current.score === 0) {
      resetGame();
    }
  }, [gameState, resetGame]);

  const handleBuyItem = (item: UpgradeOption) => {
    if (playerRef.current.credits >= item.cost) {
        playerRef.current.credits -= item.cost;
        item.apply(playerRef.current);
        setCurrentCredits(playerRef.current.credits);

        if (item.type === 'gun') {
            setShopItems(prev => prev.filter(i => i.id !== item.id));
        }
    }
  };

  const handleNextWave = () => {
      setShopOpen(false);
      projectilesRef.current = [];
      powerUpsRef.current = [];

      levelRef.current++;
      setLevel(levelRef.current);

      if (nextWaveConfigRef.current) {
        spawnWave(nextWaveConfigRef.current);
        nextWaveConfigRef.current = null;
      } else {
        spawnWave(fallbackWave);
      }
      queueNextWave();
  };

  // Main Game Loop
  useEffect(() => {
    if (gameState !== GameState.PLAYING || shopOpen) return;

    let animationFrameId: number;
    let lastTime = performance.now();
    let fireCooldown = 0;

    const spawnParticle = (x: number, y: number, color: string, count: number = 5, speedMod: number = 10) => {
      for (let i = 0; i < count; i++) {
        particlesRef.current.push({
          id: Math.random(),
          x, y,
          width: 0, height: 0,
          vx: (Math.random() - 0.5) * speedMod,
          vy: (Math.random() - 0.5) * speedMod,
          color,
          life: 1.0,
          maxLife: 1.0,
          size: Math.random() * 4 + 2,
          markedForDeletion: false
        });
      }
    };

    const update = (time: number) => {
      const dt = (time - lastTime) / 1000;
      lastTime = time;

      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');

      if (!canvas || !ctx) return;

      // Clear canvas
      ctx.fillStyle = '#050505';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // --- PLAYER UPDATE ---
      const player = playerRef.current;
      const speed = player.moveSpeed;

      // Keyboard Movement
      if (keysRef.current['ArrowLeft'] || keysRef.current['KeyA']) player.x -= speed * dt;
      if (keysRef.current['ArrowRight'] || keysRef.current['KeyD']) player.x += speed * dt;
      if (keysRef.current['ArrowUp'] || keysRef.current['KeyW']) player.y -= speed * dt;
      if (keysRef.current['ArrowDown'] || keysRef.current['KeyS']) player.y += speed * dt;

      // Joystick Movement (Mobile)
      if (leftStick.current.active) {
          player.x += leftStick.current.valX * speed * dt;
          player.y += leftStick.current.valY * speed * dt;
      }

      // Clamp player
      player.x = Math.max(0, Math.min(CANVAS_WIDTH - player.width, player.x));
      player.y = Math.max(0, Math.min(CANVAS_HEIGHT - player.height, player.y));

      // Rotation (Aim)
      if (rightStick.current.active) {
          // Mobile aim
          if (Math.abs(rightStick.current.valX) > 0.1 || Math.abs(rightStick.current.valY) > 0.1) {
              player.rotation = Math.atan2(rightStick.current.valY, rightStick.current.valX);
          }
      } else {
          // Mouse aim
          const centerX = player.x + player.width / 2;
          const centerY = player.y + player.height / 2;
          const dx = mouseRef.current.x - centerX;
          const dy = mouseRef.current.y - centerY;
          player.rotation = Math.atan2(dy, dx);
      }

      // Shooting Logic
      if (mouseDownRef.current && fireCooldown <= 0) {
        const centerX = player.x + player.width / 2;
        const centerY = player.y + player.height / 2;
        const gunLength = 25;
        const spawnX = centerX + Math.cos(player.rotation) * gunLength;
        const spawnY = centerY + Math.sin(player.rotation) * gunLength;
        const damageMult = 1 + (player.weaponLevel * 0.2);

        if (player.gunType === 'blaster') {
            const projSpeed = 800;
            const baseDamage = 15 * damageMult;
            const cooldown = Math.max(0.08, 0.2 - (player.weaponLevel * 0.02));

            projectilesRef.current.push({
               id: Math.random(),
               x: spawnX, y: spawnY, width: 6, height: 6,
               color: '#60a5fa',
               vx: Math.cos(player.rotation) * projSpeed,
               vy: Math.sin(player.rotation) * projSpeed,
               markedForDeletion: false,
               damage: baseDamage, isEnemy: false
            });

            if (player.weaponLevel >= 3) {
                projectilesRef.current.push({
                    id: Math.random(),
                    x: spawnX, y: spawnY, width: 6, height: 6,
                    color: '#60a5fa',
                    vx: Math.cos(player.rotation - 0.1) * projSpeed,
                    vy: Math.sin(player.rotation - 0.1) * projSpeed,
                    markedForDeletion: false,
                    damage: baseDamage, isEnemy: false
                 });
            }
            fireCooldown = cooldown;

        } else if (player.gunType === 'spread') {
            const projSpeed = 600;
            const baseDamage = 8 * damageMult;
            const shotCount = 3 + player.weaponLevel; // 3 to 8 shots
            const arc = 0.5; // Radians spread

            for (let i = 0; i < shotCount; i++) {
                const angle = player.rotation - (arc/2) + (arc * i / (shotCount-1));
                const jitter = (Math.random() - 0.5) * 0.1;
                projectilesRef.current.push({
                    id: Math.random(),
                    x: spawnX, y: spawnY, width: 5, height: 5,
                    color: '#a78bfa',
                    vx: Math.cos(angle + jitter) * projSpeed,
                    vy: Math.sin(angle + jitter) * projSpeed,
                    markedForDeletion: false,
                    damage: baseDamage, isEnemy: false
                 });
            }
            fireCooldown = 0.4; 

        } else if (player.gunType === 'plasma') {
            const projSpeed = 400;
            const baseDamage = 50 * damageMult;

            projectilesRef.current.push({
                id: Math.random(),
                x: spawnX, y: spawnY, width: 20, height: 20,
                color: '#ef4444',
                vx: Math.cos(player.rotation) * projSpeed,
                vy: Math.sin(player.rotation) * projSpeed,
                markedForDeletion: false,
                damage: baseDamage, isEnemy: false, piercing: true
             });
             fireCooldown = 0.6;
        }
      }
      fireCooldown -= dt;

      // --- PROJECTILES ---
      projectilesRef.current.forEach(p => {
        p.x += p.vx * dt;
        p.y += p.vy * dt;
        if (p.x < -50 || p.x > CANVAS_WIDTH + 50 || p.y < -50 || p.y > CANVAS_HEIGHT + 50) {
          p.markedForDeletion = true;
        }
      });

      // --- ENEMIES & LEVEL CLEAR ---
      if (enemiesRef.current.length === 0 && !shopOpen) {
          setFlavorText("SECTOR SECURED. ACCESSING MARKET...");
          generateShopItems();
          setShopOpen(true);
      }

      enemiesRef.current.forEach(enemy => {
        // --- MOVEMENT LOGIC ---
        if (enemy.type === 'kamikaze') {
            const dx = player.x - enemy.x;
            const dy = player.y - enemy.y;
            const distance = Math.sqrt(dx*dx + dy*dy);
            if (distance > 0) {
                enemy.vx = (dx / distance) * enemy.vy * 4;
                enemy.vy = (dy / distance) * enemy.vy * 4;
                enemy.x += enemy.vx * dt * 60;
                enemy.y += enemy.vy * dt * 60;
            }
        } else if (enemy.type === 'turret') {
            if (enemy.y < CANVAS_HEIGHT * 0.2) {
                enemy.y += enemy.vy * 30 * dt;
            } else {
                enemy.y += Math.sin(time / 1000 + enemy.id) * 0.2;
            }
            enemy.x += Math.cos(time / 1500 + enemy.id) * 0.2;
        } else {
            enemy.y += enemy.vy * 60 * dt; 
            enemy.x += Math.sin(time / 500 + enemy.id) * 2; 
        }

        // --- COLLISION WITH PLAYER ---
        if (
            player.hp > 0 &&
            enemy.x < player.x + player.width &&
            enemy.x + enemy.width > player.x &&
            enemy.y < player.y + player.height &&
            enemy.y + enemy.height > player.y
        ) {
            if (Date.now() > player.invulnerableUntil) {
                 if (enemy.type === 'kamikaze') {
                     player.hp -= 40;
                     enemy.hp = 0;
                     spawnParticle(enemy.x + enemy.width/2, enemy.y + enemy.height/2, '#ef4444', 20);
                 } else {
                     player.hp -= 15;
                     enemy.hp -= 20;
                 }
                 setLives(player.hp);
                 player.invulnerableUntil = Date.now() + 500;
                 if (player.hp <= 0) onGameOver(player.score);
            }
        }

        if (enemy.y > CANVAS_HEIGHT) {
          enemy.markedForDeletion = true;
          player.score = Math.max(0, player.score - 50); 
        }

        if (enemy.hp <= 0) {
             enemy.markedForDeletion = true;
             player.score += enemy.scoreValue;
             player.credits += enemy.creditsValue;
             spawnParticle(enemy.x + enemy.width/2, enemy.y + enemy.height/2, enemy.color, 15);

             if (Math.random() < 0.05) {
                 powerUpsRef.current.push({
                     id: Math.random(),
                     x: enemy.x + enemy.width/2 - 10, y: enemy.y + enemy.height/2 - 10,
                     width: 20, height: 20, color: '#f43f5e',
                     vx: 0, vy: 60, markedForDeletion: false,
                     type: 'health', value: 1
                 });
             }
        }

        // --- ENEMY SHOOTING ---
        if (enemy.type !== 'kamikaze' && !enemy.markedForDeletion) {
             let fireRate = 0.005;
             if (enemy.type === 'turret') fireRate = 0.025;
             if (enemy.type === 'boss') fireRate = 0.03;

             if (Math.random() < fireRate * (levelRef.current * 0.5)) {
               const ex = enemy.x + enemy.width/2;
               const ey = enemy.y + enemy.height;
               const angleToPlayer = Math.atan2(player.y - ey, player.x - ex);

               let vx = 0; let vy = 300; const speed = 350;
               if (enemy.type === 'turret' || enemy.type === 'boss' || (levelRef.current > 2 && Math.random() > 0.5)) {
                   vx = Math.cos(angleToPlayer) * speed;
                   vy = Math.sin(angleToPlayer) * speed;
               }
               projectilesRef.current.push({
                id: Math.random(), x: ex, y: ey, width: 6, height: 6,
                color: enemy.type === 'turret' ? '#f59e0b' : '#ef4444',
                vx: vx, vy: vy, markedForDeletion: false,
                damage: enemy.type === 'turret' ? 15 : 10, isEnemy: true
              });
            }
        }
      });

      // --- POWERUPS UPDATE ---
      powerUpsRef.current.forEach(p => {
        p.y += p.vy * dt;
        if (
            p.x < player.x + player.width &&
            p.x + p.width > player.x &&
            p.y < player.y + player.height &&
            p.y + p.height > player.y
        ) {
            p.markedForDeletion = true;
            spawnParticle(p.x + p.width/2, p.y + p.height/2, '#f43f5e', 10);
            if (p.type === 'health') {
                player.hp = Math.min(player.maxHp, player.hp + 50);
                setLives(player.hp);
                setFlavorText("HULL REPAIRED");
            }
        }
        if (p.y > CANVAS_HEIGHT) p.markedForDeletion = true;
      });

      // --- COLLISION PROJECTILES ---
      projectilesRef.current.forEach(proj => {
        if (proj.markedForDeletion) return;

        if (proj.isEnemy) {
            // Hit Player
            if (
                proj.x < player.x + player.width &&
                proj.x + proj.width > player.x &&
                proj.y < player.y + player.height &&
                proj.y + proj.height > player.y
            ) {
                 if (Date.now() > player.invulnerableUntil) {
                     player.hp -= proj.damage;
                     proj.markedForDeletion = true;
                     spawnParticle(player.x + player.width/2, player.y + player.height/2, '#ef4444', 10);
                     if (player.hp <= 0) onGameOver(player.score);
                     setLives(player.hp);
                 }
            }
        } else {
            // Hit Enemy
            let hit = false;
            enemiesRef.current.forEach(enemy => {
                if (!enemy.markedForDeletion &&
                    proj.x < enemy.x + enemy.width &&
                    proj.x + proj.width > enemy.x &&
                    proj.y < enemy.y + enemy.height &&
                    proj.y + proj.height > enemy.y
                ) {
                    enemy.hp -= proj.damage;
                    hit = true;
                    spawnParticle(proj.x, proj.y, proj.color, 3);
                }
            });
            if (hit && !proj.piercing) proj.markedForDeletion = true;
        }
      });

      setScore(player.score);

      // --- PARTICLES ---
      particlesRef.current.forEach(p => {
        p.x += p.vx; p.y += p.vy;
        p.life -= dt * 2;
        if (p.life <= 0) p.markedForDeletion = true;
      });

      // Cleanup
      enemiesRef.current = enemiesRef.current.filter(e => !e.markedForDeletion);
      projectilesRef.current = projectilesRef.current.filter(p => !p.markedForDeletion);
      particlesRef.current = particlesRef.current.filter(p => !p.markedForDeletion);
      powerUpsRef.current = powerUpsRef.current.filter(p => !p.markedForDeletion);

      // --- DRAWING ---

      // Draw PowerUps
      powerUpsRef.current.forEach(p => {
          ctx.fillStyle = p.color;
          ctx.fillRect(p.x, p.y, p.width, p.height);
          ctx.fillStyle = 'white';
          ctx.font = 'bold 12px monospace';
          ctx.fillText("+", p.x + 6, p.y + 14);
      });

      // Draw Player
      if (player.hp > 0) {
          ctx.save();
          const cx = player.x + player.width / 2;
          const cy = player.y + player.height / 2;
          ctx.translate(cx, cy);
          ctx.rotate(player.rotation);

          ctx.fillStyle = player.color;
          ctx.beginPath();
          ctx.arc(0, 0, player.width / 2, 0, Math.PI * 2);
          ctx.fill();

          // Gun Visuals based on Type
          if (player.gunType === 'blaster') {
            ctx.fillStyle = '#60a5fa';
            ctx.fillRect(0, -4, 25, 8); 
          } else if (player.gunType === 'spread') {
            ctx.fillStyle = '#a78bfa';
            ctx.fillRect(0, -8, 20, 6); 
            ctx.fillRect(0, 2, 20, 6); 
            ctx.fillRect(0, -3, 24, 6);
          } else if (player.gunType === 'plasma') {
            ctx.fillStyle = '#ef4444';
            ctx.beginPath();
            ctx.arc(15, 0, 8, 0, Math.PI * 2);
            ctx.fill();
          }

          ctx.fillStyle = '#bfdbfe';
          ctx.beginPath();
          ctx.arc(4, 0, 6, -Math.PI/4, Math.PI/4);
          ctx.fill();
          ctx.restore();
      }

      // Draw Enemies
      enemiesRef.current.forEach(e => {
          ctx.fillStyle = e.color;
          if (e.type === 'kamikaze') {
              const angle = Math.atan2(e.vy, e.vx);
              ctx.save();
              ctx.translate(e.x + e.width/2, e.y + e.height/2);
              ctx.rotate(angle);
              ctx.beginPath();
              ctx.moveTo(10, 0); ctx.lineTo(-10, -8); ctx.lineTo(-6, 0); ctx.lineTo(-10, 8);
              ctx.closePath(); ctx.fill(); ctx.restore();
          } else if (e.type === 'turret') {
              ctx.beginPath();
              const r = e.width/2; const cx = e.x + r; const cy = e.y + r;
              for (let i = 0; i < 8; i++) {
                  const theta = (i * Math.PI * 2) / 8;
                  const px = cx + Math.cos(theta) * r; const py = cy + Math.sin(theta) * r;
                  if (i===0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
              }
              ctx.closePath(); ctx.fill();
              const angleToPlayer = Math.atan2(player.y - cy, player.x - cx);
              ctx.save(); ctx.translate(cx, cy); ctx.rotate(angleToPlayer);
              ctx.fillStyle = '#444'; ctx.fillRect(0, -5, 25, 10); ctx.restore();
          } else {
              ctx.fillRect(e.x, e.y, e.width, e.height);
              ctx.fillStyle = 'rgba(0,0,0,0.3)';
              ctx.fillRect(e.x + e.width * 0.2, e.y + e.height * 0.5, e.width * 0.2, e.height * 0.2);
              ctx.fillRect(e.x + e.width * 0.6, e.y + e.height * 0.5, e.width * 0.2, e.height * 0.2);
          }
          if (e.maxHp > 20) {
              const hpPct = e.hp / e.maxHp;
              ctx.fillStyle = 'red'; ctx.fillRect(e.x, e.y - 10, e.width, 4);
              ctx.fillStyle = 'green'; ctx.fillRect(e.x, e.y - 10, e.width * hpPct, 4);
          }
      });

      // Draw Projectiles
      projectilesRef.current.forEach(p => {
          ctx.fillStyle = p.color;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.width/2, 0, Math.PI * 2);
          ctx.fill();
      });

      // Draw Particles
      particlesRef.current.forEach(p => {
          ctx.globalAlpha = p.life;
          ctx.fillStyle = p.color;
          ctx.fillRect(p.x, p.y, p.size, p.size);
          ctx.globalAlpha = 1.0;
      });

      // Draw Virtual Joysticks (Mobile)
      if (leftStick.current.active) {
         ctx.strokeStyle = 'rgba(59, 130, 246, 0.5)';
         ctx.lineWidth = 2;
         ctx.beginPath();
         ctx.arc(leftStick.current.originX, leftStick.current.originY, 50, 0, Math.PI*2);
         ctx.stroke();
         ctx.fillStyle = 'rgba(59, 130, 246, 0.8)';
         ctx.beginPath();
         ctx.arc(leftStick.current.currX, leftStick.current.currY, 20, 0, Math.PI*2);
         ctx.fill();
      }
      if (rightStick.current.active) {
         ctx.strokeStyle = 'rgba(239, 68, 68, 0.5)';
         ctx.lineWidth = 2;
         ctx.beginPath();
         ctx.arc(rightStick.current.originX, rightStick.current.originY, 50, 0, Math.PI*2);
         ctx.stroke();
         ctx.fillStyle = 'rgba(239, 68, 68, 0.8)';
         ctx.beginPath();
         ctx.arc(rightStick.current.currX, rightStick.current.currY, 20, 0, Math.PI*2);
         ctx.fill();
      }

      // Draw Cursor (only if not using touch)
      if (!rightStick.current.active && !leftStick.current.active) {
        ctx.strokeStyle = '#22d3ee'; ctx.lineWidth = 2;
        ctx.beginPath(); ctx.arc(mouseRef.current.x, mouseRef.current.y, 8, 0, Math.PI * 2); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(mouseRef.current.x - 12, mouseRef.current.y); ctx.lineTo(mouseRef.current.x + 12, mouseRef.current.y);
        ctx.moveTo(mouseRef.current.x, mouseRef.current.y - 12); ctx.lineTo(mouseRef.current.x, mouseRef.current.y + 12); ctx.stroke();
      }

      animationFrameId = requestAnimationFrame(update);
    };

    animationFrameId = requestAnimationFrame(update);
    return () => cancelAnimationFrame(animationFrameId);
  }, [gameState, onGameOver, setLives, setScore, spawnWave, queueNextWave, setLevel, shopOpen]);

  return (
    <div 
        ref={containerRef}
        className="relative rounded-lg overflow-hidden shadow-2xl border-2 border-slate-800 cursor-none touch-none"
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
    >
      <canvas
        ref={canvasRef}
        width={CANVAS_WIDTH}
        height={CANVAS_HEIGHT}
        className="bg-black block w-full max-w-[800px] h-auto"
      />
      <div className="scanlines"></div>

      {/* Wave Loading */}
      {enemiesRef.current.length === 0 && !shopOpen && gameState === GameState.PLAYING && (
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-green-400 font-mono text-xl animate-pulse pointer-events-none select-none">
          SCANNING FOR HOSTILES...
        </div>
      )}

      {/* Pause Button */}
      {gameState === GameState.PLAYING && !shopOpen && (
          <button 
            onClick={(e) => { e.stopPropagation(); setGameState(GameState.PAUSED); }}
            className="absolute top-4 right-4 z-20 p-2 bg-slate-900/50 border border-slate-600 text-white rounded hover:bg-slate-800 transition-colors"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="6" y="4" width="4" height="16"></rect><rect x="14" y="4" width="4" height="16"></rect></svg>
          </button>
      )}

      {/* Shop Overlay */}
      {shopOpen && (
        <div className="absolute inset-0 bg-black/95 flex flex-col items-center justify-center z-30 animate-in fade-in cursor-default p-4 sm:p-8 overflow-y-auto">
           <div className="w-full max-w-4xl flex justify-between items-center mb-8 border-b-2 border-cyan-800 pb-4">
              <h2 className="text-2xl sm:text-4xl font-bold text-cyan-400 tracking-widest uppercase">Armory</h2>
              <div className="flex items-center gap-2">
                 <span className="text-slate-400 font-mono text-sm sm:text-base">CR:</span>
                 <span className="text-xl sm:text-3xl text-yellow-400 font-mono font-bold tracking-widest">{currentCredits}</span>
              </div>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-6 w-full mb-8">
             {shopItems.map((item) => (
               <div
                 key={item.id}
                 className={`relative flex flex-col p-4 bg-slate-900 border border-slate-700 rounded-sm hover:border-cyan-500 transition-all group ${currentCredits < item.cost ? 'opacity-50 grayscale' : 'hover:-translate-y-1 hover:shadow-[0_0_15px_rgba(6,182,212,0.3)]'}`}
               >
                 <div className="absolute top-0 right-0 p-1 bg-slate-800 text-xs font-mono text-slate-400 border-l border-b border-slate-700">MK-{Math.floor(Math.random()*9)}</div>

                 <div className="h-24 w-full mb-4 bg-slate-950 flex items-center justify-center border border-slate-800 relative overflow-hidden">
                    <div className="absolute inset-0 opacity-20 bg-[linear-gradient(45deg,transparent_25%,rgba(255,255,255,0.05)_25%,rgba(255,255,255,0.05)_50%,transparent_50%,transparent_75%,rgba(255,255,255,0.05)_75%,rgba(255,255,255,0.05)_100%)] bg-[length:10px_10px]" />
                    <div className="w-12 h-12 rounded-full shadow-[0_0_20px_currentColor]" style={{ backgroundColor: item.color, color: item.color }} />
                 </div>

                 <h3 className="text-lg font-bold text-white mb-1 font-mono truncate">{item.title}</h3>
                 <p className="text-xs text-slate-400 font-mono mb-4 h-8">{item.description}</p>

                 <button
                    onClick={() => handleBuyItem(item)}
                    disabled={currentCredits < item.cost}
                    className="mt-auto py-2 bg-slate-800 hover:bg-cyan-700 disabled:hover:bg-slate-800 disabled:cursor-not-allowed text-white font-mono text-sm border border-slate-600 hover:border-cyan-400 transition-colors flex justify-between px-3"
                 >
                    <span>BUY</span>
                    <span className="text-yellow-400">{item.cost}</span>
                 </button>
               </div>
             ))}
           </div>

           <button 
             onClick={handleNextWave}
             className="w-full sm:w-auto px-12 py-4 bg-gradient-to-r from-cyan-600 to-blue-600 hover:from-cyan-500 hover:to-blue-500 text-white font-bold tracking-widest text-xl border-2 border-cyan-400 shadow-[0_0_30px_rgba(6,182,212,0.4)] transition-all transform hover:scale-105"
           >
             LAUNCH MISSION
           </button>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GameState, Player, Enemy, Projectile, Particle, WaveConfig, PowerUp, UpgradeOption } from '../types';
import { generateWave, fallbackWave } from '../services/geminiService';

interface GameCanvasProps {
  gameState: GameState;
  setGameState: (state: GameState) => void;
  setScore: (score: number) => void;
  setLives: (lives: number) => void;
  setLevel: (level: number) => void;
  setFlavorText: (text: string) => void;
  onGameOver: (finalScore: number) => void;
}

const CANVAS_WIDTH = 800;
const CANVAS_HEIGHT = 600;

export const GameCanvas: React.FC<GameCanvasProps> = ({
  gameState,
  setGameState,
  setScore,
  setLives,
  setLevel,
  setFlavorText,
  onGameOver
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Mutable game state refs
  const playerRef = useRef<Player>({
    id: 0, x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT - 100,
    width: 30, height: 30, color: '#3b82f6',
    vx: 0, vy: 0, markedForDeletion: false,
    hp: 100, maxHp: 100, weaponLevel: 1, score: 0, credits: 0, invulnerableUntil: 0,
    rotation: -Math.PI / 2,
    gunType: 'blaster',
    moveSpeed: 300
  });

  const enemiesRef = useRef<Enemy[]>([]);
  const projectilesRef = useRef<Projectile[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const powerUpsRef = useRef<PowerUp[]>([]);
  const keysRef = useRef<{ [key: string]: boolean }>({});

  // Mouse state
  const mouseRef = useRef({ x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2 });
  const mouseDownRef = useRef(false);

  // Joystick state for mobile
  const leftStick = useRef({ active: false, id: -1, originX: 0, originY: 0, currX: 0, currY: 0, valX: 0, valY: 0 });
  const rightStick = useRef({ active: false, id: -1, originX: 0, originY: 0, currX: 0, currY: 0, valX: 0, valY: 0 });

  const levelRef = useRef(1);
  const wavePendingRef = useRef(false);
  const nextWaveConfigRef = useRef<WaveConfig | null>(null);

  // Shop State
  const [shopOpen, setShopOpen] = useState(false);
  const [shopItems, setShopItems] = useState<UpgradeOption[]>([]);
  const [currentCredits, setCurrentCredits] = useState(0);

  // Initialize controls
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      keysRef.current[e.code] = true;
      if (e.code === 'Escape' && gameState === GameState.PLAYING && !shopOpen) {
        setGameState(GameState.PAUSED);
      } else if (e.code === 'Escape' && gameState === GameState.PAUSED) {
        setGameState(GameState.PLAYING);
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      keysRef.current[e.code] = false;
    };

    const handleMouseMove = (e: MouseEvent) => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      const scaleX = canvas.width / rect.width;
      const scaleY = canvas.height / rect.height;

      mouseRef.current = {
        x: (e.clientX - rect.left) * scaleX,
        y: (e.clientY - rect.top) * scaleY
      };
    };

    const handleMouseDown = (e: MouseEvent) => {
      if (e.button === 0) mouseDownRef.current = true;
    };

    const handleMouseUp = () => {
      mouseDownRef.current = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [gameState, setGameState, shopOpen]);

  // Touch Handlers
  const handleTouchStart = (e: React.TouchEvent) => {
    e.preventDefault(); // Prevent scrolling
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    const scaleX = CANVAS_WIDTH / rect.width;
    const scaleY = CANVAS_HEIGHT / rect.height;

    Array.from(e.changedTouches).forEach((touch: React.Touch) => {
      const x = (touch.clientX - rect.left) * scaleX;
      const y = (touch.clientY - rect.top) * scaleY;

      if (x < CANVAS_WIDTH / 2) {
        // Left Stick (Move)
        if (!leftStick.current.active) {
            leftStick.current = { active: true, id: touch.identifier, originX: x, originY: y, currX: x, currY: y, valX: 0, valY: 0 };
        }
      } else {
        // Right Stick (Aim/Shoot)
        if (!rightStick.current.active) {
            rightStick.current = { active: true, id: touch.identifier, originX: x, originY: y, currX: x, currY: y, valX: 0, valY: 0 };
            mouseDownRef.current = true; // Auto-fire on mobile aim
        }
      }
    });
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    e.preventDefault();
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    const scaleX = CANVAS_WIDTH / rect.width;
    const scaleY = CANVAS_HEIGHT / rect.height;

    Array.from(e.changedTouches).forEach((touch: React.Touch) => {
       const x = (touch.clientX - rect.left) * scaleX;
       const y = (touch.clientY - rect.top) * scaleY;
       const maxDist = 50; // Max radius of joystick

       if (leftStick.current.active && leftStick.current.id === touch.identifier) {
          leftStick.current.currX = x;
          leftStick.current.currY = y;
          let dx = x - leftStick.current.originX;
          let dy = y - leftStick.current.originY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist > maxDist) {
             dx = (dx / dist) * maxDist;
             dy = (dy / dist) * maxDist;
             leftStick.current.currX = leftStick.current.originX + dx;
             leftStick.current.currY = leftStick.current.originY + dy;
          }
          leftStick.current.valX = dx / maxDist;
          leftStick.current.valY = dy / maxDist;
       }

       if (rightStick.current.active && rightStick.current.id === touch.identifier) {
          rightStick.current.currX = x;
          rightStick.current.currY = y;
          let dx = x - rightStick.current.originX;
          let dy = y - rightStick.current.originY;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist > maxDist) {
             dx = (dx / dist) * maxDist;
             dy = (dy / dist) * maxDist;
             rightStick.current.currX = rightStick.current.originX + dx;
             rightStick.current.currY = rightStick.current.originY + dy;
          }
          rightStick.current.valX = dx / maxDist;
          rightStick.current.valY = dy / maxDist;
       }
    });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    e.preventDefault();
    Array.from(e.changedTouches).forEach((touch: React.Touch) => {
       if (leftStick.current.active && leftStick.current.id === touch.identifier) {
          leftStick.current.active = false;
          leftStick.current.valX = 0;
          leftStick.current.valY = 0;
       }
       if (rightStick.current.active && rightStick.current.id === touch.identifier) {
          rightStick.current.active = false;
          mouseDownRef.current = false;
       }
    });
  };

  // Generate Shop Items
  const generateShopItems = useCallback(() => {
    const player = playerRef.current;

    const allUpgrades: UpgradeOption[] = [
      {
        id: 'repair',
        title: 'HULL PATCH',
        description: 'Repair 50 HP',
        type: 'heal',
        cost: 100,
        color: '#4ade80',
        apply: (p) => { p.hp = Math.min(p.maxHp, p.hp + 50); setLives(p.hp); }
      },
      {
        id: 'maxhp',
        title: 'TITANIUM PLATING',
        description: '+50 Max HP',
        type: 'stat',
        cost: 300,
        color: '#10b981',
        apply: (p) => { p.maxHp += 50; p.hp += 50; setLives(p.hp); }
      },
      {
        id: 'speed',
        title: 'NITRO INJECTOR',
        description: '+10% Speed',
        type: 'stat',
        cost: 200,
        color: '#06b6d4',
        apply: (p) => { p.moveSpeed *= 1.1; }
      },
      {
        id: 'weapon_power',
        title: 'CORE OVERCLOCK',
        description: '+1 Weapon Level',
        type: 'stat',
        cost: 500 * player.weaponLevel,
        color: '#f59e0b',
        apply: (p) => { p.weaponLevel += 1; }
      }
    ];

    // Gun swaps (Expensive)
    if (player.gunType !== 'blaster') {
      allUpgrades.push({
        id: 'gun_blaster',
        title: 'PULSE RIFLE',
        description: 'Balanced rapid fire.',
        type: 'gun',
        cost: 800,
        color: '#3b82f6',
        apply: (p) => { p.gunType = 'blaster'; }
      });
    }
    if (player.gunType !== 'spread') {
      allUpgrades.push({
        id: 'gun_spread',
        title: 'FLAK CANNON',
        description: 'Wide spread shot.',
        type: 'gun',
        cost: 1200,
        color: '#8b5cf6',
        apply: (p) => { p.gunType = 'spread'; }
      });
    }
    if (player.gunType !== 'plasma') {
      allUpgrades.push({
        id: 'gun_plasma',
        title: 'PLASMA CASTER',
        description: 'High damage bolts.',
        type: 'gun',
        cost: 1500,
        color: '#ef4444',
        apply: (p) => { p.gunType = 'plasma'; }
      });
    }

    // Select 4 random items
    const shuffled = allUpgrades.sort(() => 0.5 - Math.random());
    setShopItems(shuffled.slice(0, 4));
    setCurrentCredits(player.credits);
  }, [setLives]);

  // Pre-fetch next wave
  const queueNextWave = useCallback(async () => {
    if (wavePendingRef.current) return;
    wavePendingRef.current = true;

    const healthPercent = Math.round((playerRef.current.hp / playerRef.current.maxHp) * 100);
    const context = `Player HP: ${healthPercent}%, Gun: ${playerRef.current.gunType}, Weapon Level: ${playerRef.current.weaponLevel}.`;

    try {
      const wave = await generateWave(levelRef.current + 1, context);
      nextWaveConfigRef.current = wave;
    } catch (e) {
      nextWaveConfigRef.current = fallbackWave;
    } finally {
      wavePendingRef.current = false;
    }
  }, []);

  // Spawn a wave
  const spawnWave = useCallback((config: WaveConfig) => {
    setFlavorText(config.flavorText);
    const newEnemies: Enemy[] = [];
    let idCounter = Date.now();

    config.enemies.forEach((group) => {
      for (let i = 0; i < group.count; i++) {
        let w = 40, h = 40;
        if (group.type === 'boss') { w = 100; h = 100; }
        else if (group.type === 'tank' || group.type === 'turret') { w = 60; h = 60; }
        else if (group.type === 'kamikaze') { w = 25; h = 25; }

        newEnemies.push({
          id: idCounter++,
          x: Math.random() * (CANVAS_WIDTH - 60) + 30,
          y: -Math.random() * 200 - 50, 
          width: w,
          height: h,
          color: group.color,
          vx: (Math.random() - 0.5) * group.speed,
          vy: group.speed * 0.5,
          markedForDeletion: false,
          hp: group.hp,
          maxHp: group.hp,
          type: group.type,
          scoreValue: group.hp * 10,
          creditsValue: Math.max(10, Math.floor(group.hp * 1.5))
        });
      }
    });
    enemiesRef.current = [...enemiesRef.current, ...newEnemies];
  }, [setFlavorText]);

  // Reset Game
  const resetGame = useCallback(() => {
    playerRef.current = {
      id: 0, x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT - 100,
      width: 30, height: 30, color: '#3b82f6',
      vx: 0, vy: 0, markedForDeletion: false,
      hp: 100, maxHp: 100, weaponLevel: 1, score: 0, credits: 0, invulnerableUntil: 0,
      rotation: -Math.PI / 2,
      gunType: 'blaster',
      moveSpeed: 300
    };
    enemiesRef.current = [];
    projectilesRef.current = [];
    particlesRef.current = [];
    powerUpsRef.current = [];
    levelRef.current = 1;
    setScore(0);
    setLives(100);
    setLevel(1);
    setShopOpen(false);

    // Reset sticks
    leftStick.current.active = false;
    rightStick.current.active = false;
    mouseDownRef.current = false;

    spawnWave(fallbackWave);
    queueNextWave();
  }, [setScore, setLives, setLevel, queueNextWave, spawnWave]);

  useEffect(() => {
    if (gameState === GameState.PLAYING && enemiesRef.current.length === 0 && playerRef.current.score === 0) {
      resetGame();
    }
  }, [gameState, resetGame]);

  const handleBuyItem = (item: UpgradeOption) => {
    if (playerRef.current.credits >= item.cost) {
        playerRef.current.credits -= item.cost;
        item.apply(playerRef.current);
        setCurrentCredits(playerRef.current.credits);

        if (item.type === 'gun') {
            setShopItems(prev => prev.filter(i => i.id !== item.id));
        }
    }
  };

  const handleNextWave = () => {
      setShopOpen(false);
      projectilesRef.current = [];
      powerUpsRef.current = [];

      levelRef.current++;
      setLevel(levelRef.current);

      if (nextWaveConfigRef.current) {
        spawnWave(nextWaveConfigRef.current);
        nextWaveConfigRef.current = null;
      } else {
        spawnWave(fallbackWave);
      }
      queueNextWave();
  };

  // Main Game Loop
  useEffect(() => {
    if (gameState !== GameState.PLAYING || shopOpen) return;

    let animationFrameId: number;
    let lastTime = performance.now();
    let fireCooldown = 0;

    const spawnParticle = (x: number, y: number, color: string, count: number = 5, speedMod: number = 10) => {
      for (let i = 0; i < count; i++) {
        particlesRef.current.push({
          id: Math.random(),
          x, y,
          width: 0, height: 0,
          vx: (Math.random() - 0.5) * speedMod,
          vy: (Math.random() - 0.5) * speedMod,
          color,
          life: 1.0,
          maxLife: 1.0,
          size: Math.random() * 4 + 2,
          markedForDeletion: false
        });
      }
    };

    const update = (time: number) => {
      const dt = (time - lastTime) / 1000;
      lastTime = time;

      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');

      if (!canvas || !ctx) return;

      // Clear canvas
      ctx.fillStyle = '#050505';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // --- PLAYER UPDATE ---
      const player = playerRef.current;
      const speed = player.moveSpeed;

      // Keyboard Movement
      if (keysRef.current['ArrowLeft'] || keysRef.current['KeyA']) player.x -= speed * dt;
      if (keysRef.current['ArrowRight'] || keysRef.current['KeyD']) player.x += speed * dt;
      if (keysRef.current['ArrowUp'] || keysRef.current['KeyW']) player.y -= speed * dt;
      if (keysRef.current['ArrowDown'] || keysRef.current['KeyS']) player.y += speed * dt;

      // Joystick Movement (Mobile)
      if (leftStick.current.active) {
          player.x += leftStick.current.valX * speed * dt;
          player.y += leftStick.current.valY * speed * dt;
      }

      // Clamp player
      player.x = Math.max(0, Math.min(CANVAS_WIDTH - player.width, player.x));
      player.y = Math.max(0, Math.min(CANVAS_HEIGHT - player.height, player.y));

      // Rotation (Aim)
      if (rightStick.current.active) {
          // Mobile aim
          if (Math.abs(rightStick.current.valX) > 0.1 || Math.abs(rightStick.current.valY) > 0.1) {
              player.rotation = Math.atan2(rightStick.current.valY, rightStick.current.valX);
          }
      } else {
          // Mouse aim
          const centerX = player.x + player.width / 2;
          const centerY = player.y + player.height / 2;
          const dx = mouseRef.current.x - centerX;
          const dy = mouseRef.current.y - centerY;
          player.rotation = Math.atan2(dy, dx);
      }

      // Shooting Logic
      if (mouseDownRef.current && fireCooldown <= 0) {
        const centerX = player.x + player.width / 2;
        const centerY = player.y + player.height / 2;
        const gunLength = 25;
        const spawnX = centerX + Math.cos(player.rotation) * gunLength;
        const spawnY = centerY + Math.sin(player.rotation) * gunLength;
        const damageMult = 1 + (player.weaponLevel * 0.2);

        if (player.gunType === 'blaster') {
            const projSpeed = 800;
            const baseDamage = 15 * damageMult;
            const cooldown = Math.max(0.08, 0.2 - (player.weaponLevel * 0.02));

            projectilesRef.current.push({
               id: Math.random(),
               x: spawnX, y: spawnY, width: 6, height: 6,
               color: '#60a5fa',
               vx: Math.cos(player.rotation) * projSpeed,
               vy: Math.sin(player.rotation) * projSpeed,
               markedForDeletion: false,
               damage: baseDamage, isEnemy: false
            });

            if (player.weaponLevel >= 3) {
                projectilesRef.current.push({
                    id: Math.random(),
                    x: spawnX, y: spawnY, width: 6, height: 6,
                    color: '#60a5fa',
                    vx: Math.cos(player.rotation - 0.1) * projSpeed,
                    vy: Math.sin(player.rotation - 0.1) * projSpeed,
                    markedForDeletion: false,
                    damage: baseDamage, isEnemy: false
                 });
            }
            fireCooldown = cooldown;

        } else if (player.gunType === 'spread') {
            const projSpeed = 600;
            const baseDamage = 8 * damageMult;
            const shotCount = 3 + player.weaponLevel; // 3 to 8 shots
            const arc = 0.5; // Radians spread

            for (let i = 0; i < shotCount; i++) {
                const angle = player.rotation - (arc/2) + (arc * i / (shotCount-1));
                const jitter = (Math.random() - 0.5) * 0.1;
                projectilesRef.current.push({
                    id: Math.random(),
                    x: spawnX, y: spawnY, width: 5, height: 5,
                    color: '#a78bfa',
                    vx: Math.cos(angle + jitter) * projSpeed,
                    vy: Math.sin(angle + jitter) * projSpeed,
                    markedForDeletion: false,
                    damage: baseDamage, isEnemy: false
                 });
            }
            fireCooldown = 0.4; 

        } else if (player.gunType === 'plasma') {
            const projSpeed = 400;
            const baseDamage = 50 * damageMult;

            projectilesRef.current.push({
                id: Math.random(),
                x: spawnX, y: spawnY, width: 20, height: 20,
                color: '#ef4444',
                vx: Math.cos(player.rotation) * projSpeed,
                vy: Math.sin(player.rotation) * projSpeed,
                markedForDeletion: false,
                damage: baseDamage, isEnemy: false, piercing: true
             });
             fireCooldown = 0.6;
        }
      }
      fireCooldown -= dt;

      // --- PROJECTILES ---
      projectilesRef.current.forEach(p => {
        p.x += p.vx * dt;
        p.y += p.vy * dt;
        if (p.x < -50 || p.x > CANVAS_WIDTH + 50 || p.y < -50 || p.y > CANVAS_HEIGHT + 50) {
          p.markedForDeletion = true;
        }
      });

      // --- ENEMIES & LEVEL CLEAR ---
      if (enemiesRef.current.length === 0 && !shopOpen) {
          setFlavorText("SECTOR SECURED. ACCESSING MARKET...");
          generateShopItems();
          setShopOpen(true);
      }

      enemiesRef.current.forEach(enemy => {
        // --- MOVEMENT LOGIC ---
        if (enemy.type === 'kamikaze') {
            const dx = player.x - enemy.x;
            const dy = player.y - enemy.y;
            const distance = Math.sqrt(dx*dx + dy*dy);
            if (distance > 0) {
                enemy.vx = (dx / distance) * enemy.vy * 4;
                enemy.vy = (dy / distance) * enemy.vy * 4;
                enemy.x += enemy.vx * dt * 60;
                enemy.y += enemy.vy * dt * 60;
            }
        } else if (enemy.type === 'turret') {
            if (enemy.y < CANVAS_HEIGHT * 0.2) {
                enemy.y += enemy.vy * 30 * dt;
            } else {
                enemy.y += Math.sin(time / 1000 + enemy.id) * 0.2;
            }
            enemy.x += Math.cos(time / 1500 + enemy.id) * 0.2;
        } else {
            enemy.y += enemy.vy * 60 * dt; 
            enemy.x += Math.sin(time / 500 + enemy.id) * 2; 
        }

        // --- COLLISION WITH PLAYER ---
        if (
            player.hp > 0 &&
            enemy.x < player.x + player.width &&
            enemy.x + enemy.width > player.x &&
            enemy.y < player.y + player.height &&
            enemy.y + enemy.height > player.y
        ) {
            if (Date.now() > player.invulnerableUntil) {
                 if (enemy.type === 'kamikaze') {
                     player.hp -= 40;
                     enemy.hp = 0;
                     spawnParticle(enemy.x + enemy.width/2, enemy.y + enemy.height/2, '#ef4444', 20);
                 } else {
                     player.hp -= 15;
                     enemy.hp -= 20;
                 }
                 setLives(player.hp);
                 player.invulnerableUntil = Date.now() + 500;
                 if (player.hp <= 0) onGameOver(player.score);
            }
        }

        if (enemy.y > CANVAS_HEIGHT) {
          enemy.markedForDeletion = true;
          player.score = Math.max(0, player.score - 50); 
        }

        if (enemy.hp <= 0) {
             enemy.markedForDeletion = true;
             player.score += enemy.scoreValue;
             player.credits += enemy.creditsValue;
             spawnParticle(enemy.x + enemy.width/2, enemy.y + enemy.height/2, enemy.color, 15);

             if (Math.random() < 0.05) {
                 powerUpsRef.current.push({
                     id: Math.random(),
                     x: enemy.x + enemy.width/2 - 10, y: enemy.y + enemy.height/2 - 10,
                     width: 20, height: 20, color: '#f43f5e',
                     vx: 0, vy: 60, markedForDeletion: false,
                     type: 'health', value: 1
                 });
             }
        }

        // --- ENEMY SHOOTING ---
        if (enemy.type !== 'kamikaze' && !enemy.markedForDeletion) {
             let fireRate = 0.005;
             if (enemy.type === 'turret') fireRate = 0.025;
             if (enemy.type === 'boss') fireRate = 0.03;

             if (Math.random() < fireRate * (levelRef.current * 0.5)) {
               const ex = enemy.x + enemy.width/2;
               const ey = enemy.y + enemy.height;
               const angleToPlayer = Math.atan2(player.y - ey, player.x - ex);

               let vx = 0; let vy = 300; const speed = 350;
               if (enemy.type === 'turret' || enemy.type === 'boss' || (levelRef.current > 2 && Math.random() > 0.5)) {
                   vx = Math.cos(angleToPlayer) * speed;
                   vy = Math.sin(angleToPlayer) * speed;
               }
               projectilesRef.current.push({
                id: Math.random(), x: ex, y: ey, width: 6, height: 6,
                color: enemy.type === 'turret' ? '#f59e0b' : '#ef4444',
                vx: vx, vy: vy, markedForDeletion: false,
                damage: enemy.type === 'turret' ? 15 : 10, isEnemy: true
              });
            }
        }
      });

      // --- POWERUPS UPDATE ---
      powerUpsRef.current.forEach(p => {
        p.y += p.vy * dt;
        if (
            p.x < player.x + player.width &&
            p.x + p.width > player.x &&
            p.y < player.y + player.height &&
            p.y + p.height > player.y
        ) {
            p.markedForDeletion = true;
            spawnParticle(p.x + p.width/2, p.y + p.height/2, '#f43f5e', 10);
            if (p.type === 'health') {
                player.hp = Math.min(player.maxHp, player.hp + 50);
                setLives(player.hp);
                setFlavorText("HULL REPAIRED");
            }
        }
        if (p.y > CANVAS_HEIGHT) p.markedForDeletion = true;
      });

      // --- COLLISION PROJECTILES ---
      projectilesRef.current.forEach(proj => {
        if (proj.markedForDeletion) return;

        if (proj.isEnemy) {
            // Hit Player
            if (
                proj.x < player.x + player.width &&
                proj.x + proj.width > player.x &&
                proj.y < player.y + player.height &&
                proj.y + proj.height > player.y
            ) {
                 if (Date.now() > player.invulnerableUntil) {
                     player.hp -= proj.damage;
                     proj.markedForDeletion = true;
                     spawnParticle(player.x + player.width/2, player.y + player.height/2, '#ef4444', 10);
                     if (player.hp <= 0) onGameOver(player.score);
                     setLives(player.hp);
                 }
            }
        } else {
            // Hit Enemy
            let hit = false;
            enemiesRef.current.forEach(enemy => {
                if (!enemy.markedForDeletion &&
                    proj.x < enemy.x + enemy.width &&
                    proj.x + proj.width > enemy.x &&
                    proj.y < enemy.y + enemy.height &&
                    proj.y + proj.height > enemy.y
                ) {
                    enemy.hp -= proj.damage;
                    hit = true;
                    spawnParticle(proj.x, proj.y, proj.color, 3);
                }
            });
            if (hit && !proj.piercing) proj.markedForDeletion = true;
        }
      });

      setScore(player.score);

      // --- PARTICLES ---
      particlesRef.current.forEach(p => {
        p.x += p.vx; p.y += p.vy;
        p.life -= dt * 2;
        if (p.life <= 0) p.markedForDeletion = true;
      });

      // Cleanup
      enemiesRef.current = enemiesRef.current.filter(e => !e.markedForDeletion);
      projectilesRef.current = projectilesRef.current.filter(p => !p.markedForDeletion);
      particlesRef.current = particlesRef.current.filter(p => !p.markedForDeletion);
      powerUpsRef.current = powerUpsRef.current.filter(p => !p.markedForDeletion);

      // --- DRAWING ---

      // Draw PowerUps
      powerUpsRef.current.forEach(p => {
          ctx.fillStyle = p.color;
          ctx.fillRect(p.x, p.y, p.width, p.height);
          ctx.fillStyle = 'white';
          ctx.font = 'bold 12px monospace';
          ctx.fillText("+", p.x + 6, p.y + 14);
      });

      // Draw Player
      if (player.hp > 0) {
          ctx.save();
          const cx = player.x + player.width / 2;
          const cy = player.y + player.height / 2;
          ctx.translate(cx, cy);
          ctx.rotate(player.rotation);

          ctx.fillStyle = player.color;
          ctx.beginPath();
          ctx.arc(0, 0, player.width / 2, 0, Math.PI * 2);
          ctx.fill();

          // Gun Visuals based on Type
          if (player.gunType === 'blaster') {
            ctx.fillStyle = '#60a5fa';
            ctx.fillRect(0, -4, 25, 8); 
          } else if (player.gunType === 'spread') {
            ctx.fillStyle = '#a78bfa';
            ctx.fillRect(0, -8, 20, 6); 
            ctx.fillRect(0, 2, 20, 6); 
            ctx.fillRect(0, -3, 24, 6);
          } else if (player.gunType === 'plasma') {
            ctx.fillStyle = '#ef4444';
            ctx.beginPath();
            ctx.arc(15, 0, 8, 0, Math.PI * 2);
            ctx.fill();
          }

          ctx.fillStyle = '#bfdbfe';
          ctx.beginPath();
          ctx.arc(4, 0, 6, -Math.PI/4, Math.PI/4);
          ctx.fill();
          ctx.restore();
      }

      // Draw Enemies
      enemiesRef.current.forEach(e => {
          ctx.fillStyle = e.color;
          if (e.type === 'kamikaze') {
              const angle = Math.atan2(e.vy, e.vx);
              ctx.save();
              ctx.translate(e.x + e.width/2, e.y + e.height/2);
              ctx.rotate(angle);
              ctx.beginPath();
              ctx.moveTo(10, 0); ctx.lineTo(-10, -8); ctx.lineTo(-6, 0); ctx.lineTo(-10, 8);
              ctx.closePath(); ctx.fill(); ctx.restore();
          } else if (e.type === 'turret') {
              ctx.beginPath();
              const r = e.width/2; const cx = e.x + r; const cy = e.y + r;
              for (let i = 0; i < 8; i++) {
                  const theta = (i * Math.PI * 2) / 8;
                  const px = cx + Math.cos(theta) * r; const py = cy + Math.sin(theta) * r;
                  if (i===0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
              }
              ctx.closePath(); ctx.fill();
              const angleToPlayer = Math.atan2(player.y - cy, player.x - cx);
              ctx.save(); ctx.translate(cx, cy); ctx.rotate(angleToPlayer);
              ctx.fillStyle = '#444'; ctx.fillRect(0, -5, 25, 10); ctx.restore();
          } else {
              ctx.fillRect(e.x, e.y, e.width, e.height);
              ctx.fillStyle = 'rgba(0,0,0,0.3)';
              ctx.fillRect(e.x + e.width * 0.2, e.y + e.height * 0.5, e.width * 0.2, e.height * 0.2);
              ctx.fillRect(e.x + e.width * 0.6, e.y + e.height * 0.5, e.width * 0.2, e.height * 0.2);
          }
          if (e.maxHp > 20) {
              const hpPct = e.hp / e.maxHp;
              ctx.fillStyle = 'red'; ctx.fillRect(e.x, e.y - 10, e.width, 4);
              ctx.fillStyle = 'green'; ctx.fillRect(e.x, e.y - 10, e.width * hpPct, 4);
          }
      });

      // Draw Projectiles
      projectilesRef.current.forEach(p => {
          ctx.fillStyle = p.color;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.width/2, 0, Math.PI * 2);
          ctx.fill();
      });

      // Draw Particles
      particlesRef.current.forEach(p => {
          ctx.globalAlpha = p.life;
          ctx.fillStyle = p.color;
          ctx.fillRect(p.x, p.y, p.size, p.size);
          ctx.globalAlpha = 1.0;
      });

      // Draw Virtual Joysticks (Mobile)
      if (leftStick.current.active) {
         ctx.strokeStyle = 'rgba(59, 130, 246, 0.5)';
         ctx.lineWidth = 2;
         ctx.beginPath();
         ctx.arc(leftStick.current.originX, leftStick.current.originY, 50, 0, Math.PI*2);
         ctx.stroke();
         ctx.fillStyle = 'rgba(59, 130, 246, 0.8)';
         ctx.beginPath();
         ctx.arc(leftStick.current.currX, leftStick.current.currY, 20, 0, Math.PI*2);
         ctx.fill();
      }
      if (rightStick.current.active) {
         ctx.strokeStyle = 'rgba(239, 68, 68, 0.5)';
         ctx.lineWidth = 2;
         ctx.beginPath();
         ctx.arc(rightStick.current.originX, rightStick.current.originY, 50, 0, Math.PI*2);
         ctx.stroke();
         ctx.fillStyle = 'rgba(239, 68, 68, 0.8)';
         ctx.beginPath();
         ctx.arc(rightStick.current.currX, rightStick.current.currY, 20, 0, Math.PI*2);
         ctx.fill();
      }

      // Draw Cursor (only if not using touch)
      if (!rightStick.current.active && !leftStick.current.active) {
        ctx.strokeStyle = '#22d3ee'; ctx.lineWidth = 2;
        ctx.beginPath(); ctx.arc(mouseRef.current.x, mouseRef.current.y, 8, 0, Math.PI * 2); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(mouseRef.current.x - 12, mouseRef.current.y); ctx.lineTo(mouseRef.current.x + 12, mouseRef.current.y);
        ctx.moveTo(mouseRef.current.x, mouseRef.current.y - 12); ctx.lineTo(mouseRef.current.x, mouseRef.current.y + 12); ctx.stroke();
      }

      animationFrameId = requestAnimationFrame(update);
    };

    animationFrameId = requestAnimationFrame(update);
    return () => cancelAnimationFrame(animationFrameId);
  }, [gameState, onGameOver, setLives, setScore, spawnWave, queueNextWave, setLevel, shopOpen]);

  return (
    <div 
        ref={containerRef}
        className="relative rounded-lg overflow-hidden shadow-2xl border-2 border-slate-800 cursor-none touch-none"
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
    >
      <canvas
        ref={canvasRef}
        width={CANVAS_WIDTH}
        height={CANVAS_HEIGHT}
        className="bg-black block w-full max-w-[800px] h-auto"
      />
      <div className="scanlines"></div>

      {/* Wave Loading */}
      {enemiesRef.current.length === 0 && !shopOpen && gameState === GameState.PLAYING && (
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-green-400 font-mono text-xl animate-pulse pointer-events-none select-none">
          SCANNING FOR HOSTILES...
        </div>
      )}

      {/* Pause Button */}
      {gameState === GameState.PLAYING && !shopOpen && (
          <button 
            onClick={(e) => { e.stopPropagation(); setGameState(GameState.PAUSED); }}
            className="absolute top-4 right-4 z-20 p-2 bg-slate-900/50 border border-slate-600 text-white rounded hover:bg-slate-800 transition-colors"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="6" y="4" width="4" height="16"></rect><rect x="14" y="4" width="4" height="16"></rect></svg>
          </button>
