      {/* Header / HUD */}
      <div className="w-full max-w-[800px] flex justify-between items-end mb-2 sm:mb-4 font-mono px-4 sm:px-0 pt-2 sm:pt-0">
        <div>
          <h1 className="text-xl sm:text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-blue-600 truncate">
            GEMINI STARFIGHTER
          </h1>
          <p className="text-slate-400 text-xs sm:text-sm mt-1 h-6 truncate max-w-[200px] sm:max-w-none">{flavorText}</p>
        </div>
        <div className="text-right">
           <div className="text-[10px] sm:text-sm text-slate-500">SCORE</div>
           <div className="text-xl sm:text-2xl text-white font-bold tracking-widest">{score.toString().padStart(6, '0')}</div>
        </div>
      </div>

      {/* Main Game Container */}
      <div className="relative group w-full max-w-[800px]">
        <GameCanvas 
          gameState={gameState}
          setGameState={setGameState}
          setScore={setScore}
          setLives={setLives}
          setLevel={setLevel}
          setFlavorText={setFlavorText}
