        {/* Start Menu Overlay */}
        {gameState === GameState.MENU && (
          <div className="absolute inset-0 bg-black/90 flex flex-row items-stretch justify-center z-20 backdrop-blur-sm overflow-hidden">
            {/* Left: Menu */}
            <div className="flex-1 flex flex-col items-center justify-center p-8 border-r border-slate-800">
                <h2 className="text-3xl sm:text-5xl font-bold text-white mb-8 tracking-tighter text-center">READY PLAYER ONE</h2>
                <button 
                  onClick={handleStartGame}
