                >
                  INITIATE LAUNCH
                </button>
                <div className="text-slate-500 mt-8 font-mono text-sm text-center">
                  <p className="hidden sm:block">WASD / ARROWS to Move • MOUSE to Aim & Shoot</p>
                  <p className="sm:hidden text-cyan-400 animate-pulse">USE DUAL THUMBSTICKS TO PLAY</p>
                  <p className="sm:hidden text-xs mt-1">Left Stick: Move • Right Stick: Aim & Fire</p>
