            {/* Right: Leaderboard */}
            <div className="w-48 sm:w-64 bg-slate-900/50 p-4 sm:p-6 flex flex-col border-l border-slate-800 hidden sm:flex">
                <h3 className="text-cyan-400 font-bold mb-4 tracking-widest text-center border-b border-cyan-900 pb-2">TOP ACES</h3>
