            )}

            <button 
              onClick={handleStartGame}
              className="px-8 py-4 bg-transparent hover:bg-red-900/50 text-white font-bold border-2 border-red-400 shadow-[0_0_20px_rgba(248,113,113,0.5)] transition-all transform hover:scale-105 active:scale-95"
            >
              RETRY MISSION
            </button>
          </div>
        )}

        {/* Pause Overlay */}
         {gameState === GameState.PAUSED && (
          <div className="absolute inset-0 bg-black/60 flex flex-col items-center justify-center text-center z-20 backdrop-blur-sm">
