        </div>
        <div className="text-right">
           <div className="text-[10px] sm:text-sm text-slate-500 uppercase">Score</div>
           <div className="text-xl sm:text-2xl text-white font-bold tracking-widest">{score.toString().padStart(6, '0')}</div>
        </div>
      </div>

      {/* Main Game Container */}
      <div className="relative group w-full max-w-[800px] shrink-0">
        <GameCanvas 
          gameState={gameState}
          setGameState={setGameState}
          setScore={setScore}
          setLives={setLives}
          setLevel={setLevel}
          setFlavorText={setFlavorText}
          onGameOver={handleGameOver}
        />

        {/* Start Menu Overlay */}
        {gameState === GameState.MENU && (
          <div className="absolute inset-0 bg-black/90 flex flex-row items-stretch justify-center z-20 backdrop-blur-sm overflow-hidden">
